var QUESTIONS_THEORY_2 = [
{type:"mcq",diff:"easy",en:{q:"Who is considered the father of the computer?",opts:["Charles Babbage","Alan Turing","John von Neumann","Blaise Pascal"],ans:0,exp:"Charles Babbage invented the Analytical Engine in 1833. It had a mill, store, reader, and printer, which function similarly to a modern CPU, memory, and I/O devices, earning him the title of 'Father of the Computer'."},hi:{q:"कंप्यूटर का जनक किसे माना जाता है?",opts:["चार्ल्स बैबेज","एलन ट्यूरिंग","जॉन वॉन न्यूमैन","ब्लेज पास्कल"],ans:0,exp:"चार्ल्स बैबेज ने 1833 में एनालिटिकल इंजन का आविष्कार किया था। इसमें मिल, स्टोर, रीडर और प्रिंटर थे, जो आधुनिक सीपीयू, मेमोरी और इनपुट/आउटपुट डिवाइस के समान कार्य करते थे, इसलिए उन्हें 'कंप्यूटर का जनक' कहा जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"What was the main electronic component of first-generation computers?",opts:["Vacuum tubes","Transistors","Integrated Circuits","Microprocessors"],ans:0,exp:"First-generation computers (1946-1954) used vacuum tubes or electronic valves as their main electronic component. These tubes consumed a lot of power, produced excessive heat, and were very costly to maintain."},hi:{q:"पहली पीढ़ी के कंप्यूटरों का मुख्य इलेक्ट्रॉनिक घटक क्या था?",opts:["वैक्यूम ट्यूब","ट्रांजिस्टर","इंटीग्रेटेड सर्किट","माइक्रोप्रोसेसर"],ans:0,exp:"पहली पीढ़ी के कंप्यूटरों (1946-1954) में मुख्य इलेक्ट्रॉनिक घटक के रूप में वैक्यूम ट्यूब या इलेक्ट्रॉनिक वाल्व का उपयोग किया जाता था। ये ट्यूब बहुत अधिक बिजली की खपत करते थे और अत्यधिक गर्मी पैदा करते थे।"}},
{type:"mcq",diff:"easy",en:{q:"Which generation of computers used transistors as their primary CPU component?",opts:["First Generation","Second Generation","Third Generation","Fourth Generation"],ans:1,exp:"The second-generation computers (1955-1964) replaced vacuum tubes with transistors for CPU components. This transition significantly reduced the size, cost, and heat generation while improving overall processing speed and reliability."},hi:{q:"किस पीढ़ी के कंप्यूटरों ने अपने प्राथमिक सीपीयू घटक के रूप में ट्रांजिस्टर का उपयोग किया?",opts:["पहली पीढ़ी","दूसरी पीढ़ी","तीसरी पीढ़ी","चौथी पीढ़ी"],ans:1,exp:"दूसरी पीढ़ी के कंप्यूटरों (1955-1964) ने सीपीयू घटकों के लिए वैक्यूम ट्यूबों को ट्रांजिस्टर से बदल दिया। इस बदलाव ने आकार, लागत और गर्मी उत्पादन को काफी कम कर दिया और प्रसंस्करण गति में सुधार किया।"}},
{type:"mcq",diff:"easy",en:{q:"What does ENIAC stand for?",opts:["Electronic Numerical Integrator and Calculator","Electrical Network Integrated and Computer","Electronic Number Interpolator and Calculator","Electrical Numerical Integration and Computation"],ans:0,exp:"ENIAC stands for Electronic Numerical Integrator and Calculator. Built in 1946 at the University of Pennsylvania, it was the first electronic computer, containing 18,000 vacuum tubes and weighing 30 tons."},hi:{q:"ENIAC का पूर्ण रूप क्या है?",opts:["इलेक्ट्रॉनिक न्यूमेरिकल इंटीग्रेटर एंड कैलकुलेटर","इलेक्ट्रिकल नेटवर्क इंटीग्रेटेड एंड कंप्यूटर","इलेक्ट्रॉनिक नंबर इंटरपोलेटर एंड कैलकुलेटर","इलेक्ट्रिकल न्यूमेरिकल इंटीग्रेशन एंड कंप्यूटेशन"],ans:0,exp:"ENIAC का पूर्ण रूप 'इलेक्ट्रॉनिक न्यूमेरिकल इंटीग्रेटर एंड कैलकुलेटर' है। 1946 में पेंसिल्वेनिया विश्वविद्यालय में निर्मित, यह पहला इलेक्ट्रॉनिक कंप्यूटर था, जिसमें 18,000 वैक्यूम ट्यूब थे और इसका वजन 30 टन था।"}},
{type:"mcq",diff:"easy",en:{q:"The third generation of computers replaced transistors with:",opts:["Integrated Circuits (ICs)","Large Scale Integration (LSI)","Vacuum Tubes","Very Large Scale Integration (VLSI)"],ans:0,exp:"Third-generation computers (1964-1977) utilized Integrated Circuits (ICs), which consisted of the capacity of 300 transistors on a single silicon chip. This greatly reduced the size and cost of computers."},hi:{q:"तीसरी पीढ़ी के कंप्यूटरों ने ट्रांजिस्टर को किसके साथ बदल दिया?",opts:["इंटीग्रेटेड सर्किट्स (ICs)","लार्ज स्केल इंटीग्रेशन (LSI)","वैक्यूम ट्यूब","वेरी लार्ज स्केल इंटीग्रेशन (VLSI)"],ans:0,exp:"तीसरी पीढ़ी के कंप्यूटरों (1964-1977) में इंटीग्रेटेड सर्किट्स (ICs) का उपयोग किया गया, जिसमें एक ही सिलिकॉन चिप पर 300 ट्रांजिस्टर की क्षमता शामिल थी। इससे कंप्यूटर का आकार और लागत काफी कम हो गई।"}},
{type:"mcq",diff:"easy",en:{q:"What does VLSI stand for in computer architecture?",opts:["Very Large Scale Integration","Variable Large Scale Integration","Very Long Scale Integration","Virtual Large Scale Integration"],ans:0,exp:"VLSI stands for Very Large Scale Integration. It refers to an IC containing more than 1,000 components, allowing the entire Central Processing Unit (CPU) to be placed on a single chip, creating microcomputers."},hi:{q:"कंप्यूटर आर्किटेक्चर में VLSI का पूर्ण रूप क्या है?",opts:["वेरी लार्ज स्केल इंटीग्रेशन","वेरिएबल लार्ज स्केल इंटीग्रेशन","वेरी लॉन्ग स्केल इंटीग्रेशन","वर्चुअल लार्ज स्केल इंटीग्रेशन"],ans:0,exp:"VLSI का पूर्ण रूप वेरी लार्ज स्केल इंटीग्रेशन है। यह 1,000 से अधिक घटकों वाले IC को संदर्भित करता है, जिससे संपूर्ण सेंट्रल प्रोसेसिंग यूनिट (CPU) को एक चिप पर रखा जा सकता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which type of computer measures continuously changing physical quantities like pressure and temperature?",opts:["Analog computer","Digital computer","Hybrid computer","Mainframe computer"],ans:0,exp:"An analog computer measures continuously changing physical quantities such as current, temperature, and pressure. It converts them into continuous quantities for computation, giving approximate results, unlike digital computers."},hi:{q:"किस प्रकार का कंप्यूटर दबाव और तापमान जैसी लगातार बदलती भौतिक मात्राओं को मापता है?",opts:["एनालॉग कंप्यूटर","डिजिटल कंप्यूटर","हाइब्रिड कंप्यूटर","मेनफ्रेम कंप्यूटर"],ans:0,exp:"एक एनालॉग कंप्यूटर लगातार बदलती भौतिक मात्राओं जैसे कि करंट, तापमान और दबाव को मापता है। यह गणना के लिए उन्हें निरंतर मात्रा में परिवर्तित करता है, जो डिजिटल कंप्यूटरों के विपरीत अनुमानित परिणाम देता है।"}},
{type:"mcq",diff:"easy",en:{q:"A digital computer primarily operates using which number system?",opts:["Binary number system","Decimal number system","Octal number system","Hexadecimal number system"],ans:0,exp:"A digital computer works with digital data and relies exclusively on the binary number system. It represents data in digital signals where '0' signifies an OFF state and '1' signifies an ON state for logic operations."},hi:{q:"एक डिजिटल कंप्यूटर मुख्य रूप से किस संख्या प्रणाली का उपयोग करके काम करता है?",opts:["बाइनरी नंबर सिस्टम","दशमलव नंबर सिस्टम","ऑक्टल नंबर सिस्टम","हेक्साडेसिमल नंबर सिस्टम"],ans:0,exp:"एक डिजिटल कंप्यूटर डिजिटल डेटा के साथ काम करता है और विशेष रूप से बाइनरी नंबर सिस्टम पर निर्भर करता है। यह डिजिटल सिग्नल में डेटा का प्रतिनिधित्व करता है जहां '0' का अर्थ OFF और '1' का अर्थ ON होता है।"}},
{type:"mcq",diff:"easy",en:{q:"A computer system that combines the operational characteristics of both analog and digital computers is called a:",opts:["Hybrid computer","Super computer","Mini computer","Micro computer"],ans:0,exp:"A hybrid computer integrates the best features of both analog and digital computers. It can accept, process, and handle data in both analog and digital forms, often used in specialized medical and scientific equipment."},hi:{q:"वह कंप्यूटर सिस्टम जो एनालॉग और डिजिटल दोनों कंप्यूटरों की परिचालन विशेषताओं को जोड़ता है, क्या कहलाता है?",opts:["हाइब्रिड कंप्यूटर","सुपर कंप्यूटर","मिनी कंप्यूटर","माइक्रो कंप्यूटर"],ans:0,exp:"हाइब्रिड कंप्यूटर एनालॉग और डिजिटल दोनों कंप्यूटरों की बेहतरीन विशेषताओं को एकीकृत करता है। यह एनालॉग और डिजिटल दोनों रूपों में डेटा को स्वीकार और संसाधित कर सकता है, जिसका उपयोग अक्सर चिकित्सा उपकरणों में होता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which category of computer is structurally the biggest, most expensive, and fastest?",opts:["Super computer","Mainframe computer","Microcomputer","Minicomputer"],ans:0,exp:"Super computers are the fastest, largest, and most expensive computers available. They process trillions of instructions per second and are designed for highly calculation-intensive tasks like weather forecasting and missile design."},hi:{q:"संरचनात्मक रूप से सबसे बड़ा, सबसे महंगा और सबसे तेज कंप्यूटर की श्रेणी कौन सी है?",opts:["सुपर कंप्यूटर","मेनफ्रेम कंप्यूटर","माइक्रो कंप्यूटर","मिनीकंप्यूटर"],ans:0,exp:"सुपर कंप्यूटर सबसे तेज़, सबसे बड़े और सबसे महंगे कंप्यूटर हैं। वे प्रति सेकंड ट्रिलियन निर्देशों को संसाधित करते हैं और मौसम पूर्वानुमान तथा मिसाइल डिजाइन जैसे अत्यधिक गणना-गहन कार्यों के लिए डिज़ाइन किए गए हैं।"}},
{type:"mcq",diff:"easy",en:{q:"What does the acronym CPU stand for in a computer system?",opts:["Central Processing Unit","Central Program Unit","Core Processing Unit","Control Processing Unit"],ans:0,exp:"CPU stands for Central Processing Unit. It is often referred to as the electronic brain of the computer, responsible for carrying out program instructions by performing basic arithmetical, logical, and I/O operations."},hi:{q:"कंप्यूटर सिस्टम में CPU का पूर्ण रूप क्या है?",opts:["सेंट्रल प्रोसेसिंग यूनिट","सेंट्रल प्रोग्राम यूनिट","कोर प्रोसेसिंग यूनिट","कंट्रोल प्रोसेसिंग यूनिट"],ans:0,exp:"CPU का अर्थ है सेंट्रल प्रोसेसिंग यूनिट (Central Processing Unit)। इसे अक्सर कंप्यूटर का इलेक्ट्रॉनिक मस्तिष्क कहा जाता है, जो बुनियादी अंकगणितीय, तार्किक और I/O संचालन करके प्रोग्राम निर्देशों को पूरा करने के लिए जिम्मेदार है।"}},
{type:"mcq",diff:"easy",en:{q:"Which essential sub-component of the CPU is strictly responsible for performing mathematical calculations?",opts:["Arithmetic Logic Unit (ALU)","Control Unit (CU)","Memory Unit (MU)","Switched Mode Power Supply (SMPS)"],ans:0,exp:"The Arithmetic Logic Unit (ALU) is the critical component of the CPU that handles all arithmetic calculations (like addition and subtraction) and logical operations (like comparisons)."},hi:{q:"सीपीयू का कौन सा आवश्यक उप-घटक गणितीय गणना करने के लिए पूरी तरह जिम्मेदार है?",opts:["अर्थमैटिक लॉजिक यूनिट (ALU)","कंट्रोल यूनिट (CU)","मेमोरी यूनिट (MU)","स्विच्ड मोड पावर सप्लाई (SMPS)"],ans:0,exp:"अर्थमैटिक लॉजिक यूनिट (ALU) सीपीयू का वह महत्वपूर्ण घटक है जो सभी अंकगणितीय गणनाओं (जैसे जोड़ और घटाव) और तार्किक संचालन (जैसे तुलना) को संभालता है।"}},
{type:"mcq",diff:"easy",en:{q:"The main printed circuit board that acts as the foundation of a computer is called:",opts:["Motherboard","Daughterboard","SMPS","BIOS"],ans:0,exp:"The motherboard is a large printed circuit board containing tiny electronic circuits. It serves as the computer's foundation, enabling the CPU, RAM, and all peripheral hardware components to communicate and function together."},hi:{q:"कंप्यूटर की नींव के रूप में कार्य करने वाले मुख्य मुद्रित सर्किट बोर्ड (Printed Circuit Board) को क्या कहा जाता है?",opts:["मदरबोर्ड","डॉटरबोर्ड","SMPS","BIOS"],ans:0,exp:"मदरबोर्ड एक बड़ा मुद्रित सर्किट बोर्ड है जिसमें छोटे इलेक्ट्रॉनिक सर्किट होते हैं। यह कंप्यूटर की नींव के रूप में कार्य करता है, जिससे सीपीयू, रैम और सभी हार्डवेयर घटक एक साथ संवाद करने में सक्षम होते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which type of standard port is historically used to connect a keyboard and a mouse?",opts:["PS/2 port","Serial port","Parallel port","VGA port"],ans:0,exp:"Standard keyboards and mice often connect to the computer via PS/2 (Personal System 2) ports. These are color-coded circular connectors, typically purple for the keyboard and green for the mouse."},hi:{q:"कीबोर्ड और माउस को जोड़ने के लिए ऐतिहासिक रूप से किस प्रकार के मानक पोर्ट का उपयोग किया जाता है?",opts:["PS/2 पोर्ट","सीरियल पोर्ट","पैरेलल पोर्ट","VGA पोर्ट"],ans:0,exp:"मानक कीबोर्ड और माउस अक्सर PS/2 (पर्सनल सिस्टम 2) पोर्ट के माध्यम से कंप्यूटर से जुड़ते हैं। ये रंग-कोडित गोलाकार कनेक्टर होते हैं, आमतौर पर कीबोर्ड के लिए बैंगनी और माउस के लिए हरे।"}},
{type:"mcq",diff:"easy",en:{q:"What does SMPS stand for in desktop computer hardware?",opts:["Switched Mode Power Supply","Single Mode Power Supply","Switched Memory Power System","Sequential Mode Power Supply"],ans:0,exp:"SMPS stands for Switched Mode Power Supply. It is an internal power supply unit that converts the AC input from the mains into stable DC output voltages (like 5V and 12V) required by internal components."},hi:{q:"डेस्कटॉप कंप्यूटर हार्डवेयर में SMPS का पूर्ण रूप क्या है?",opts:["स्विच्ड मोड पावर सप्लाई","सिंगल मोड पावर सप्लाई","स्विच्ड मेमोरी पावर सिस्टम","सीक्वेंशियल मोड पावर सप्लाई"],ans:0,exp:"SMPS का अर्थ है स्विच्ड मोड पावर सप्लाई (Switched Mode Power Supply)। यह एक आंतरिक विद्युत आपूर्ति इकाई है जो मेन से एसी इनपुट को आंतरिक घटकों द्वारा आवश्यक स्थिर डीसी आउटपुट (जैसे 5V और 12V) में परिवर्तित करती है।"}},
{type:"mcq",diff:"easy",en:{q:"The color-coded PS/2 port specifically designed for a keyboard is usually:",opts:["Purple","Green","Blue","Yellow"],ans:0,exp:"PS/2 connectors are universally color-coded to prevent incorrect cable insertion. The purple PS/2 connector is specifically designated for the keyboard, while the green connector is strictly meant for the mouse."},hi:{q:"कीबोर्ड के लिए विशेष रूप से डिज़ाइन किया गया रंग-कोडित PS/2 पोर्ट आमतौर पर होता है:",opts:["बैंगनी","हरा","नीला","पीला"],ans:0,exp:"गलत केबल प्रविष्टि को रोकने के लिए PS/2 कनेक्टर सार्वभौमिक रूप से रंग-कोडित होते हैं। बैंगनी PS/2 कनेक्टर विशेष रूप से कीबोर्ड के लिए होता है, जबकि हरा कनेक्टर माउस के लिए होता है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the full form of USB?",opts:["Universal Serial Bus","Uniform Serial Bus","Universal System Bus","Universal Standard Bus"],ans:0,exp:"USB stands for Universal Serial Bus. It is a highly popular standard interface for connecting external devices like digital cameras, scanners, and printers, heavily favored due to its hot-swappable plug-and-play features."},hi:{q:"USB का पूर्ण रूप क्या है?",opts:["यूनिवर्सल सीरियल बस","यूनिफ़ॉर्म सीरियल बस","यूनिवर्सल सिस्टम बस","यूनिवर्सल स्टैण्डर्ड बस"],ans:0,exp:"USB का अर्थ यूनिवर्सल सीरियल बस है। यह डिजिटल कैमरा, स्कैनर और प्रिंटर जैसे बाहरी उपकरणों को जोड़ने के लिए एक अत्यधिक लोकप्रिय मानक इंटरफ़ेस है।"}},
{type:"mcq",diff:"easy",en:{q:"What does the acronym RAM primarily stand for?",opts:["Random Access Memory","Read Access Memory","Rapid Access Memory","Random Allocation Memory"],ans:0,exp:"RAM stands for Random-Access Memory. It is the primary, volatile memory used by the CPU to temporarily store actively running programs and data for rapid access and execution."},hi:{q:"RAM का पूर्ण रूप मुख्य रूप से क्या है?",opts:["रैंडम एक्सेस मेमोरी","रीड एक्सेस मेमोरी","रैपिड एक्सेस मेमोरी","रैंडम एलोकेशन मेमोरी"],ans:0,exp:"RAM का अर्थ रैंडम-एक्सेस मेमोरी है। यह एक प्राथमिक और अस्थायी मेमोरी है जिसका उपयोग CPU द्वारा सक्रिय रूप से चल रहे प्रोग्राम और डेटा को स्टोर करने के लिए किया जाता है।"}},
{type:"mcq",diff:"easy",en:{q:"In computing terms, what does BIOS stand for?",opts:["Basic Input Output System","Base Input Output System","Basic Internal Output System","Binary Input Output System"],ans:0,exp:"BIOS stands for Basic Input-Output System. It is the built-in firmware recorded on a ROM or flash memory chip that initializes the hardware and determines computer capability before the OS is loaded."},hi:{q:"कंप्यूटिंग शब्दों में, BIOS का क्या अर्थ है?",opts:["बेसिक इनपुट आउटपुट सिस्टम","बेस इनपुट आउटपुट सिस्टम","बेसिक इंटरनल आउटपुट सिस्टम","बाइनरी इनपुट आउटपुट सिस्टम"],ans:0,exp:"BIOS का अर्थ बेसिक इनपुट-आउटपुट सिस्टम है। यह ROM या फ्लैश मेमोरी चिप पर रिकॉर्ड किया गया अंतर्निहित फर्मवेयर है जो ओएस (OS) लोड होने से पहले हार्डवेयर को प्रारंभ करता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which component on the motherboard is responsible for maintaining the BIOS settings and system time when the PC is off?",opts:["CMOS battery","Lithium battery","BIOS battery","ROM battery"],ans:0,exp:"The CMOS (Complementary Metal-Oxide-Semiconductor) battery is a small power cell on the motherboard. It continually supplies power to store vital BIOS configurations and keep the system clock ticking when the PC is unplugged."},hi:{q:"मदरबोर्ड पर कौन सा घटक पीसी बंद होने पर BIOS सेटिंग्स और सिस्टम समय को बनाए रखने के लिए जिम्मेदार है?",opts:["CMOS बैटरी","लिथियम बैटरी","BIOS बैटरी","ROM बैटरी"],ans:0,exp:"CMOS बैटरी मदरबोर्ड पर एक छोटा पावर सेल है। यह महत्वपूर्ण BIOS कॉन्फ़िगरेशन को संग्रहीत करने के लिए निरंतर शक्ति की आपूर्ति करता है और पीसी के प्लग न होने पर सिस्टम घड़ी को चालू रखता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which port found on the motherboard's back panel is primarily designed to provide access to integrated video output?",opts:["VGA port","LAN port","Audio port","Serial port"],ans:0,exp:"The VGA (Video Graphics Array) port is specifically designed to provide access to integrated video output. It typically uses a 15-pin D-subminiature connector to connect the computer to a monitor or display."},hi:{q:"मदरबोर्ड के बैक पैनल पर पाया जाने वाला कौन सा पोर्ट मुख्य रूप से एकीकृत वीडियो आउटपुट तक पहुंच प्रदान करने के लिए डिज़ाइन किया गया है?",opts:["VGA पोर्ट","LAN पोर्ट","ऑडियो पोर्ट","सीरियल पोर्ट"],ans:0,exp:"वीजीए (VGA - वीडियो ग्राफिक्स ऐरे) पोर्ट विशेष रूप से एकीकृत वीडियो आउटपुट तक पहुंच प्रदान करने के लिए डिज़ाइन किया गया है। यह मॉनिटर को कंप्यूटर से जोड़ता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which modern cable standard provides significantly faster hard drive access speeds compared to the older IDE interface?",opts:["SATA","IDE","PATA","SCSI"],ans:0,exp:"SATA (Serial Advanced Technology Attachment) cables are the modern standard for connecting hard drives and optical drives to the motherboard, replacing older IDE cables by providing much faster data transfer speeds."},hi:{q:"पुराने IDE इंटरफ़ेस की तुलना में कौन सा आधुनिक केबल मानक काफी तेज़ हार्ड ड्राइव एक्सेस गति प्रदान करता है?",opts:["SATA","IDE","PATA","SCSI"],ans:0,exp:"SATA (सीरियल एडवांस्ड टेक्नोलॉजी अटैचमेंट) केबल हार्ड ड्राइव और ऑप्टिकल ड्राइव को मदरबोर्ड से जोड़ने के लिए आधुनिक मानक हैं, जो पुराने IDE केबलों की जगह तेज़ गति प्रदान करते हैं।"}},
{type:"mcq",diff:"easy",en:{q:"Which built-in component specifically cools down the Switched Mode Power Supply (SMPS) unit?",opts:["Exhaust fan","CPU fan","Case fan","RAM cooling fan"],ans:0,exp:"The SMPS includes a small attached fan known as the exhaust fan. It continuously rotates as long as the computer remains switched on, dedicated solely to preventing the SMPS unit from overheating."},hi:{q:"कौन सा अंतर्निहित (built-in) घटक विशेष रूप से स्विच्ड मोड पावर सप्लाई (SMPS) यूनिट को ठंडा करता है?",opts:["एक्जॉस्ट फैन","सीपीयू फैन","केस फैन","रैम कूलिंग फैन"],ans:0,exp:"SMPS में एक छोटा सा पंखा जुड़ा होता है जिसे एक्जॉस्ट फैन (exhaust fan) के रूप में जाना जाता है। जब तक कंप्यूटर चालू रहता है, यह लगातार घूमता रहता है, ताकि SMPS को अधिक गर्म होने से बचाया जा सके।"}},
{type:"mcq",diff:"easy",en:{q:"In the context of hard disk partitioning, what does the acronym MBR stand for?",opts:["Master Boot Record","Main Boot Record","Master Boot Routine","Memory Boot Record"],ans:0,exp:"MBR stands for Master Boot Record. It is a critical 512-byte partition located at the very first physical sector of a hard disk (CHS 0,0,1) containing the bootstrap program and the partition table."},hi:{q:"हार्ड डिस्क विभाजन के संदर्भ में, MBR का पूर्ण रूप क्या है?",opts:["मास्टर बूट रिकॉर्ड","मेन बूट रिकॉर्ड","मास्टर बूट रूटीन","मेमोरी बूट रिकॉर्ड"],ans:0,exp:"MBR का अर्थ मास्टर बूट रिकॉर्ड है। यह हार्ड डिस्क के पहले भौतिक सेक्टर (CHS 0,0,1) पर स्थित एक महत्वपूर्ण 512-बाइट विभाजन है जिसमें बूटस्ट्रैप प्रोग्राम और पार्टीशन टेबल शामिल है।"}},
{type:"mcq",diff:"easy",en:{q:"What is the very first system process that begins immediately after a computer is switched on?",opts:["POST","Booting","BIOS loading","OS loading"],ans:0,exp:"When a computer is switched on, the very first process initiated by the BIOS is to conduct a POST (Power-On Self-Test). This routine verifies that all fundamental hardware devices are functioning smoothly."},hi:{q:"कंप्यूटर चालू होने के तुरंत बाद शुरू होने वाली सबसे पहली सिस्टम प्रक्रिया क्या है?",opts:["POST","बूटिंग","BIOS लोडिंग","OS लोडिंग"],ans:0,exp:"जब एक कंप्यूटर चालू किया जाता है, तो BIOS द्वारा शुरू की गई सबसे पहली प्रक्रिया POST (पावर-ऑन सेल्फ-टेस्ट) होती है। यह जाँच करता है कि सभी मूलभूत हार्डवेयर सुचारू रूप से कार्य कर रहे हैं या नहीं।"}},
{type:"mcq",diff:"easy",en:{q:"What is the full form of POST in the system booting sequence?",opts:["Power On Self Test","Power Off Self Test","Program On Self Test","Power On System Test"],ans:0,exp:"POST stands for Power-On Self-Test. It is a diagnostic testing sequence executed by the BIOS to verify that essential hardware components like RAM and hard disks are connected and operating correctly without faults."},hi:{q:"सिस्टम बूटिंग अनुक्रम में POST का पूर्ण रूप क्या है?",opts:["पावर ऑन सेल्फ टेस्ट","पावर ऑफ सेल्फ टेस्ट","प्रोग्राम ऑन सेल्फ टेस्ट","पावर ऑन सिस्टम टेस्ट"],ans:0,exp:"POST का अर्थ पावर-ऑन सेल्फ-टेस्ट (Power-On Self-Test) है। यह BIOS द्वारा निष्पादित एक नैदानिक परीक्षण अनुक्रम है जो यह सत्यापित करता है कि RAM और हार्ड डिस्क जैसे आवश्यक हार्डवेयर ठीक से काम कर रहे हैं या नहीं।"}},
{type:"mcq",diff:"easy",en:{q:"How many data bits are transferred simultaneously when using a parallel port interface?",opts:["8 bits","4 bits","16 bits","32 bits"],ans:0,exp:"Unlike a serial port which queues and sends bits one by one, a parallel port allows for the simultaneous transfer of all eight bits of a byte across multiple physical data lines."},hi:{q:"पैरेलल पोर्ट (समानांतर पोर्ट) इंटरफ़ेस का उपयोग करते समय एक साथ कितने डेटा बिट्स स्थानांतरित किए जाते हैं?",opts:["8 बिट्स","4 बिट्स","16 बिट्स","32 बिट्स"],ans:0,exp:"सीरियल पोर्ट के विपरीत, जो बिट्स को एक-एक करके भेजता है, एक समानांतर (पैरेलल) पोर्ट आठ बिट्स (एक बाइट) को एक साथ स्थानांतरित करने की अनुमति देता है।"}},
{type:"mcq",diff:"easy",en:{q:"Which type of memory serves as the temporary storage workspace for data and programs that the CPU is actively using?",opts:["RAM","ROM","Hard Disk","Flash Drive"],ans:0,exp:"Random-Access Memory (RAM) acts as the high-speed temporary storage workspace for the CPU. Programs and data currently being executed or manipulated are loaded into RAM because accessing it is exponentially faster than accessing a hard disk."},hi:{q:"किस प्रकार की मेमोरी उन डेटा और प्रोग्राम के लिए अस्थायी स्टोरेज कार्यक्षेत्र के रूप में कार्य करती है जिनका उपयोग CPU सक्रिय रूप से कर रहा है?",opts:["रैम (RAM)","रॉम (ROM)","हार्ड डिस्क","फ्लैश ड्राइव"],ans:0,exp:"रैंडम-एक्सेस मेमोरी (RAM) CPU के लिए उच्च गति वाले अस्थायी स्टोरेज के रूप में कार्य करती है। वर्तमान में निष्पादित किए जा रहे प्रोग्राम RAM में लोड किए जाते हैं क्योंकि यह हार्ड डिस्क की तुलना में बहुत तेज़ है।"}},
{type:"tf",diff:"easy",en:{q:"First-generation computers were small in size and consumed very little electrical power.",opts:["True","False"],ans:1,exp:"First-generation computers like ENIAC were enormous, weighing up to 30 tons, occupying massive rooms, and consumed immense electrical power (around 150,000 watts) due to thousands of vacuum tubes."},hi:{q:"पहली पीढ़ी के कंप्यूटर आकार में छोटे थे और बहुत कम विद्युत शक्ति की खपत करते थे।",opts:["सही","गलत"],ans:1,exp:"ENIAC जैसे पहली पीढ़ी के कंप्यूटर बहुत विशाल थे, जिनका वजन 30 टन तक था। हजारों वैक्यूम ट्यूबों के कारण वे बड़े कमरों पर कब्जा करते थे और 150,000 वाट तक की अत्यधिक बिजली की खपत करते थे।"}},
{type:"tf",diff:"easy",en:{q:"A hybrid computer is structurally capable of accepting and processing both analog and digital data forms.",opts:["True","False"],ans:0,exp:"A hybrid computer precisely combines the continuous measurement attributes of an analog machine with the discrete logical processing of a digital computer, easily handling both analog and digital data."},hi:{q:"एक हाइब्रिड कंप्यूटर संरचनात्मक रूप से एनालॉग और डिजिटल दोनों प्रकार के डेटा को स्वीकार करने और संसाधित करने में सक्षम है।",opts:["सही","गलत"],ans:0,exp:"हाइब्रिड कंप्यूटर एनालॉग मशीन के निरंतर माप गुणों को डिजिटल कंप्यूटर के तार्किक प्रसंस्करण के साथ जोड़ता है, जिससे यह एनालॉग और डिजिटल दोनों डेटा को आसानी से संभाल सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which historical computer system is recognized as the first stored-program computer?",opts:["EDSAC","EDVAC","ENIAC","UNIVAC-1"],ans:0,exp:"EDSAC (Electronic Delay Storage Automatic Computer), developed by M.V. Wilkes at Cambridge University in 1949, holds the distinction of being the first stored-program computer, reducing the need for human physical intervention during computation."},hi:{q:"किस ऐतिहासिक कंप्यूटर सिस्टम को पहले 'संग्रहीत-प्रोग्राम कंप्यूटर' (stored-program computer) के रूप में मान्यता प्राप्त है?",opts:["EDSAC","EDVAC","ENIAC","UNIVAC-1"],ans:0,exp:"कैम्ब्रिज विश्वविद्यालय में एम.वी. विल्केस द्वारा 1949 में विकसित EDSAC को पहला संग्रहीत-प्रोग्राम कंप्यूटर (stored-program computer) होने का गौरव प्राप्त है।"}},
{type:"mcq",diff:"medium",en:{q:"In what year was the UNIVAC-1, the first commercial computer in the USA, introduced?",opts:["1951","1946","1955","1960"],ans:0,exp:"The Universal Automatic Computer (UNIVAC-1) was developed and introduced in the United States in 1951. It was heavily used for general-purpose computing and marked the advent of commercial computers with magnetic tape buffers."},hi:{q:"यूएसए में पहला वाणिज्यिक कंप्यूटर, UNIVAC-1 किस वर्ष पेश किया गया था?",opts:["1951","1946","1955","1960"],ans:0,exp:"यूनिवर्सल ऑटोमैटिक कंप्यूटर (UNIVAC-1) 1951 में संयुक्त राज्य अमेरिका में पेश किया गया था। यह वाणिज्यिक कंप्यूटरों के युग की शुरुआत का प्रतीक था।"}},
{type:"mcq",diff:"medium",en:{q:"Which significant high-level programming languages were notably developed during the second generation of computers?",opts:["FORTRAN and COBOL","C and C++","Java and Python","BASIC and PASCAL"],ans:0,exp:"During the second generation of computers (1955-1964), primitive machine languages were replaced by sophisticated high-level languages, prominently FORTRAN (developed around 1956) and COBOL (1960-1961)."},hi:{q:"कंप्यूटर की दूसरी पीढ़ी के दौरान कौन सी महत्वपूर्ण उच्च-स्तरीय प्रोग्रामिंग भाषाएं विकसित की गईं?",opts:["फोरट्रान (FORTRAN) और कोबोल (COBOL)","सी (C) और सी++ (C++)","जावा और पायथन","बेसिक और पास्कल"],ans:0,exp:"कंप्यूटर की दूसरी पीढ़ी (1955-1964) के दौरान, मशीन भाषाओं को उच्च-स्तरीय भाषाओं द्वारा प्रतिस्थापित किया गया, जिनमें प्रमुख रूप से फोरट्रान (1956 के आसपास) और कोबोल (1960-1961) थीं।"}},
{type:"mcq",diff:"medium",en:{q:"An integrated circuit (IC) that typically contains about 100 components is classified specifically as:",opts:["LSI (Large Scale Integration)","VLSI (Very Large Scale Integration)","ULSI (Ultra Large Scale Integration)","MSI (Medium Scale Integration)"],ans:0,exp:"Within third and fourth-generation terminologies, an IC incorporating approximately 100 components is designated as LSI (Large Scale Integration). Scaling beyond 1,000 components transitions the classification to VLSI."},hi:{q:"एक इंटीग्रेटेड सर्किट (IC) जिसमें आमतौर पर लगभग 100 घटक होते हैं, उसे विशेष रूप से किस रूप में वर्गीकृत किया जाता है?",opts:["LSI (लार्ज स्केल इंटीग्रेशन)","VLSI (वेरी लार्ज स्केल इंटीग्रेशन)","ULSI (अल्ट्रा लार्ज स्केल इंटीग्रेशन)","MSI (मीडियम स्केल इंटीग्रेशन)"],ans:0,exp:"तीसरी और चौथी पीढ़ी की शब्दावली के भीतर, लगभग 100 घटकों को शामिल करने वाले IC को LSI (लार्ज स्केल इंटीग्रेशन) के रूप में नामित किया गया है। 1,000 से अधिक घटक होने पर इसे VLSI कहा जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What groundbreaking technologies predominantly define the fifth generation of computers?",opts:["Artificial Intelligence and ULSI","VLSI and Microprocessors","Transistors and Core memory","ICs and LSI"],ans:0,exp:"The fifth generation (Present and Future) is defined by Ultra-Large Scale Integration (ULSI) chips containing millions of transistors and Artificial Intelligence (AI) enabling natural language and expert system capabilities."},hi:{q:"कंप्यूटर की पांचवीं पीढ़ी को मुख्य रूप से कौन सी अभूतपूर्व तकनीकें परिभाषित करती हैं?",opts:["आर्टिफिशियल इंटेलिजेंस और ULSI","VLSI और माइक्रोप्रोसेसर","ट्रांजिस्टर और कोर मेमोरी","ICs और LSI"],ans:0,exp:"पांचवीं पीढ़ी को अल्ट्रा-लार्ज स्केल इंटीग्रेशन (ULSI) चिप्स द्वारा परिभाषित किया गया है जिसमें लाखों ट्रांजिस्टर और आर्टिफिशियल इंटेलिजेंस (AI) शामिल हैं जो प्राकृतिक भाषा प्रसंस्करण को सक्षम करते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following devices operates entirely on the principles of an analog computer?",opts:["Speedometer","Laptop","Smart phone","Desktop PC"],ans:0,exp:"A traditional speedometer is an excellent practical example of an analog computer. It continually measures the varying physical quantity of rotational speed and provides a real-time analog reading on a dial."},hi:{q:"निम्नलिखित में से कौन सा उपकरण पूरी तरह से एनालॉग कंप्यूटर के सिद्धांतों पर काम करता है?",opts:["स्पीडोमीटर","लैपटॉप","स्मार्ट फोन","डेस्कटॉप पीसी"],ans:0,exp:"एक पारंपरिक स्पीडोमीटर एनालॉग कंप्यूटर का एक उत्कृष्ट व्यावहारिक उदाहरण है। यह घूर्णी गति की अलग-अलग भौतिक मात्रा को लगातार मापता है और डायल पर रीयल-टाइम एनालॉग रीडिंग प्रदान करता है।"}},
{type:"mcq",diff:"medium",en:{q:"A robust Mainframe computer system is engineered to simultaneously serve up to how many users?",opts:["Up to 50,000","Up to 4,000","Up to 1,000","Single user only"],ans:0,exp:"Mainframe computers are exceptionally powerful, large-scale machines primarily used by enterprise organizations. They are engineered for bulk transaction processing, capable of reliably serving up to 50,000 concurrent users via terminals."},hi:{q:"एक मजबूत मेनफ्रेम कंप्यूटर सिस्टम को एक साथ कितने उपयोगकर्ताओं की सेवा करने के लिए डिज़ाइन किया गया है?",opts:["50,000 तक","4,000 तक","1,000 तक","केवल एकल उपयोगकर्ता"],ans:0,exp:"मेनफ्रेम कंप्यूटर असाधारण रूप से शक्तिशाली और बड़े पैमाने की मशीनें हैं जिनका उपयोग मुख्य रूप से संगठनों द्वारा किया जाता है। वे टर्मिनलों के माध्यम से 50,000 समवर्ती उपयोगकर्ताओं की मज़बूती से सेवा करने में सक्षम हैं।"}},
{type:"mcq",diff:"medium",en:{q:"Which notable supercomputer, positioned in China, was declared the world's fastest in October 2010?",opts:["Tianhe-1A","Deep Blue","Param","CRAY-XP"],ans:0,exp:"In October 2010, the Tianhe-1A supercomputer, located in China, achieved global recognition when it was officially certified as the fastest supercomputer in the world at that time."},hi:{q:"चीन में स्थित किस उल्लेखनीय सुपरकंप्यूटर को अक्टूबर 2010 में दुनिया का सबसे तेज़ घोषित किया गया था?",opts:["तियानहे-1A (Tianhe-1A)","डीप ब्लू","परम","क्रे-एक्सपी (CRAY-XP)"],ans:0,exp:"अक्टूबर 2010 में, चीन में स्थित तियानहे-1A (Tianhe-1A) सुपरकंप्यूटर को आधिकारिक तौर पर उस समय दुनिया के सबसे तेज़ सुपरकंप्यूटर के रूप में प्रमाणित किया गया था।"}},
{type:"mcq",diff:"medium",en:{q:"The physical 'D' type connector historically utilized on motherboards for a standard Serial port is typically:",opts:["DB-9M","DB-25M","DB-15F","RJ-45"],ans:0,exp:"Serial ports typically utilize a 9-pin male 'D' style connector designated as DB-9M. The shape guarantees that the peripheral cables can only be plugged into the motherboard in one specific orientation."},hi:{q:"मानक सीरियल पोर्ट के लिए मदरबोर्ड पर ऐतिहासिक रूप से उपयोग किया जाने वाला भौतिक 'D' प्रकार का कनेक्टर आमतौर पर कौन सा होता है?",opts:["DB-9M","DB-25M","DB-15F","RJ-45"],ans:0,exp:"सीरियल पोर्ट आमतौर पर DB-9M के रूप में नामित 9-पिन मेल 'D' शैली कनेक्टर का उपयोग करते हैं। यह सुनिश्चित करता है कि केबलों को केवल एक विशिष्ट अभिविन्यास में मदरबोर्ड में प्लग किया जा सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which significant attribute allows USB devices to be inserted or removed smoothly without requiring a system restart?",opts:["Hot swappable","Cold swappable","Non-removable integrity","Fixed configuration"],ans:0,exp:"One of the most defining and popular features of Universal Serial Bus (USB) technology is that devices are 'hot swappable.' They can be safely plugged in or unplugged while the operating system is actively running."},hi:{q:"कौन सी महत्वपूर्ण विशेषता USB उपकरणों को सिस्टम पुनरारंभ (restart) किए बिना सुचारू रूप से सम्मिलित करने या हटाने की अनुमति देती है?",opts:["हॉट स्वैपेबल","कोल्ड स्वैपेबल","नॉन-रिमूवेबल इंटिग्रिटी","फिक्स्ड कॉन्फ़िगरेशन"],ans:0,exp:"यूनिवर्सल सीरियल बस (USB) तकनीक की सबसे परिभाषित विशेषताओं में से एक यह है कि डिवाइस 'हॉट स्वैपेबल' हैं। ऑपरेटिंग सिस्टम के सक्रिय रूप से चलने के दौरान उन्हें सुरक्षित रूप से प्लग इन या अनप्लग किया जा सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"A computer's Switched Mode Power Supply (SMPS) reliably converts standard AC mains input into which precise DC output voltages?",opts:["+/-12V, +/-5V, and 3.3V DC","+/-15V, +/-5V, and 1.5V DC","+/-10V, +/-3V, and 2.5V DC","+/-24V, +/-12V, and 5V DC"],ans:0,exp:"An internal SMPS meticulously regulates and converts standard 110-240V AC power into precise internal DC voltage levels, specifically +/-12-Volt, +/-5-Volt, and 3.3-Volt, to safely power sensitive motherboard components and drives."},hi:{q:"कंप्यूटर का स्विच्ड मोड पावर सप्लाई (SMPS) मानक एसी मेन इनपुट को किन सटीक डीसी आउटपुट वोल्टेज में परिवर्तित करता है?",opts:["+/-12V, +/-5V, और 3.3V DC","+/-15V, +/-5V, और 1.5V DC","+/-10V, +/-3V, और 2.5V DC","+/-24V, +/-12V, और 5V DC"],ans:0,exp:"एक आंतरिक SMPS सावधानीपूर्वक 110-240V AC पावर को सटीक आंतरिक DC वोल्टेज स्तरों में परिवर्तित करता है, विशेष रूप से +/-12-वोल्ट, +/-5-वोल्ट और 3.3-वोल्ट, ताकि मदरबोर्ड घटकों को सुरक्षित रूप से पावर मिल सके।"}},
{type:"mcq",diff:"medium",en:{q:"What is the fundamental functional purpose of an expansion slot mounted directly on a motherboard?",opts:["To connect additional peripheral cards","To connect the main power supply","To actively cool down the CPU chip","To physically store BIOS firmware settings"],ans:0,exp:"Expansion slots (like PCI, AGP, or PCIe) are specialized connectors integrated into the motherboard. They allow users to insert additional peripheral expansion cards, such as high-end video, sound, or wireless network adapters."},hi:{q:"मदरबोर्ड पर सीधे लगे एक्सपेंशन स्लॉट का मूलभूत कार्यात्मक उद्देश्य क्या है?",opts:["अतिरिक्त परिधीय कार्ड (peripheral cards) कनेक्ट करने के लिए","मुख्य बिजली आपूर्ति को जोड़ने के लिए","सीपीयू चिप को सक्रिय रूप से ठंडा करने के लिए","BIOS फर्मवेयर सेटिंग्स को भौतिक रूप से संग्रहीत करने के लिए"],ans:0,exp:"विस्तार स्लॉट (जैसे पीसीआई, एजीपी) मदरबोर्ड में एकीकृत विशेष कनेक्टर हैं। वे उपयोगकर्ताओं को हाई-एंड वीडियो, साउंड या वायरलेस नेटवर्क एडेप्टर जैसे अतिरिक्त परिधीय विस्तार कार्ड सम्मिलित करने की अनुमति देते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"The acronym DIMM, referring to the physical packaging standard for modern RAM modules, stands for:",opts:["Dual Inline Memory Module","Double Inline Memory Module","Dual Internal Memory Module","Direct Inline Memory Module"],ans:0,exp:"DIMM stands for Dual Inline Memory Module. Unlike older SIMMs (Single Inline Memory Modules), DIMMs contain independent electrical contacts on both sides of the module, doubling the data path width to modern processors."},hi:{q:"DIMM का संक्षिप्त नाम, जो आधुनिक RAM मॉड्यूल के भौतिक पैकेजिंग मानक को संदर्भित करता है, का अर्थ है:",opts:["डुअल इनलाइन मेमोरी मॉड्यूल","डबल इनलाइन मेमोरी मॉड्यूल","डुअल इंटरनल मेमोरी मॉड्यूल","डायरेक्ट इनलाइन मेमोरी मॉड्यूल"],ans:0,exp:"DIMM का पूर्ण रूप 'डुअल इनलाइन मेमोरी मॉड्यूल' (Dual Inline Memory Module) है। पुराने SIMMs के विपरीत, DIMMs में मॉड्यूल के दोनों तरफ स्वतंत्र विद्युत संपर्क होते हैं, जो प्रोसेसर के लिए डेटा पथ की चौड़ाई को दोगुना कर देते हैं।"}},
{type:"mcq",diff:"medium",en:{q:"How many electrical contact pins are characteristically found on a standard DIMM package extensively used in personal computers?",opts:["168 pins","72 pins","32 pins","128 pins"],ans:0,exp:"Historically, the prominent standard form factor for a Dual Inline Memory Module (DIMM) used extensively in SDRAM architecture features exactly 168 pins, whereas older SIMM formats used 32 or 72 pins."},hi:{q:"पर्सनल कंप्यूटरों में बड़े पैमाने पर उपयोग किए जाने वाले मानक DIMM पैकेज पर आमतौर पर कितने इलेक्ट्रिकल संपर्क पिन पाए जाते हैं?",opts:["168 पिन","72 पिन","32 पिन","128 पिन"],ans:0,exp:"ऐतिहासिक रूप से, SDRAM वास्तुकला में बड़े पैमाने पर उपयोग किए जाने वाले डुअल इनलाइन मेमोरी मॉड्यूल (DIMM) के लिए प्रमुख मानक में ठीक 168 पिन होते हैं, जबकि पुराने SIMM प्रारूपों में 32 या 72 पिन का उपयोग किया जाता था।"}},
{type:"mcq",diff:"medium",en:{q:"In motherboard architecture, what does the specific technical term 'shadowing' signify regarding the BIOS?",opts:["Copying BIOS routines from slow ROM into fast RAM","Hiding BIOS configuration settings from the OS layer","Copying RAM contents directly back into ROM","Encrypting BIOS settings to prevent unwanted access"],ans:0,exp:"Shadowing is a performance-enhancing technique where the system's BIOS firmware is systematically copied from the relatively slow ROM chip into the much faster system RAM during the boot process for quicker execution."},hi:{q:"मदरबोर्ड वास्तुकला में, विशिष्ट तकनीकी शब्द 'शैडोइंग' BIOS के संबंध में क्या दर्शाता है?",opts:["धीमी ROM से तेज़ RAM में BIOS रूटीन की प्रतिलिपि बनाना","OS परत से BIOS कॉन्फ़िगरेशन सेटिंग्स को छिपाना","रैम सामग्री को सीधे वापस रॉम (ROM) में कॉपी करना","अवांछित पहुंच को रोकने के लिए BIOS सेटिंग्स को एन्क्रिप्ट करना"],ans:0,exp:"शैडोइंग (Shadowing) एक प्रदर्शन-बढ़ाने वाली तकनीक है जहां सिस्टम के BIOS फर्मवेयर को बूट प्रक्रिया के दौरान अपेक्षाकृत धीमी ROM चिप से बहुत तेज सिस्टम रैम (RAM) में व्यवस्थित रूप से कॉपी किया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What is the primary operational function of the CMOS memory found on a modern motherboard?",opts:["To securely store BIOS configurations and keep the system time","To process and render advanced 3D graphics","To permanently store Operating System boot files","To directly regulate main power supply voltages"],ans:0,exp:"The CMOS (Complementary Metal-Oxide-Semiconductor) memory is a tiny, battery-backed volatile storage area on the motherboard. It strictly retains custom BIOS settings and keeps the Real-Time Clock running when power is disconnected."},hi:{q:"आधुनिक मदरबोर्ड पर पाई जाने वाली CMOS मेमोरी का प्राथमिक परिचालन कार्य क्या है?",opts:["BIOS कॉन्फ़िगरेशन को सुरक्षित रूप से स्टोर करना और सिस्टम का समय बनाए रखना","उन्नत 3D ग्राफिक्स को संसाधित और प्रस्तुत करना","ऑपरेटिंग सिस्टम बूट फ़ाइलों को स्थायी रूप से संग्रहीत करने के लिए","मुख्य बिजली आपूर्ति वोल्टेज को सीधे विनियमित करने के लिए"],ans:0,exp:"CMOS मेमोरी मदरबोर्ड पर एक छोटा, बैटरी-समर्थित वाष्पशील भंडारण क्षेत्र है। यह कस्टम BIOS सेटिंग्स को सख्ती से बरकरार रखता है और बिजली डिस्कनेक्ट होने पर भी रीयल-टाइम क्लॉक (Real-Time Clock) को चालू रखता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which prevalent expansion bus architecture intrinsically allows attached peripherals to directly access system memory while effectively bypassing the CPU?",opts:["PCI bus","ISA bus","USB bus","Serial bus"],ans:0,exp:"The PCI (Peripheral Component Interconnect) bus is a highly advanced, processor-independent specification. It supports 'bus mastering', which actively permits attached peripheral devices to access system memory directly, significantly offloading CPU overhead."},hi:{q:"कौन सी प्रचलित विस्तार बस वास्तुकला परिधीय उपकरणों (peripherals) को सीपीयू को बायपास करते हुए सीधे सिस्टम मेमोरी तक पहुंचने की अनुमति देती है?",opts:["PCI बस","ISA बस","USB बस","सीरियल बस"],ans:0,exp:"पीसीआई (Peripheral Component Interconnect) बस एक अत्यधिक उन्नत, प्रोसेसर-स्वतंत्र वास्तुकला है। यह 'बस मास्टरिंग' का समर्थन करता है, जो परिधीय उपकरणों को सीधे सिस्टम मेमोरी तक पहुंचने की अनुमति देता है, जिससे सीपीयू का भार काफी कम हो जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"What does the acronym AGP physically stand for in the context of motherboard slots?",opts:["Accelerated Graphics Port","Advanced Graphics Port","Active Graphics Port","Allocated Graphics Port"],ans:0,exp:"AGP stands for Accelerated Graphics Port. It is a legacy, high-speed, point-to-point channel structurally dedicated on the motherboard solely for attaching a high-performance video card to assist in 3D computer graphics acceleration."},hi:{q:"मदरबोर्ड स्लॉट के संदर्भ में AGP का पूर्ण रूप क्या है?",opts:["एक्सेलेरेटेड ग्राफिक्स पोर्ट (Accelerated Graphics Port)","एडवांस्ड ग्राफिक्स पोर्ट","एक्टिव ग्राफिक्स पोर्ट","एलोकेटेड ग्राफिक्स पोर्ट"],ans:0,exp:"AGP का अर्थ एक्सेलेरेटेड ग्राफिक्स पोर्ट है। यह एक उच्च गति वाला, पॉइंट-टू-पॉइंट चैनल है जो मदरबोर्ड पर पूरी तरह से 3D कंप्यूटर ग्राफिक्स त्वरण में सहायता के लिए उच्च प्रदर्शन वाले वीडियो कार्ड को जोड़ने के लिए समर्पित है।"}},
{type:"mcq",diff:"medium",en:{q:"The Master Boot Record (MBR) is architecturally mandated to be located at which exact physical sector of a hard disk?",opts:["CHS 0,0,1","CHS 1,0,0","CHS 0,1,0","CHS 1,1,1"],ans:0,exp:"The Master Boot Record (MBR) is structurally located at the very first physical sector of a hard disk drive, which is uniquely denoted in classical disk geometry as Cylinder 0, Head 0, and Sector 1 (CHS 0,0,1)."},hi:{q:"मास्टर बूट रिकॉर्ड (MBR) को हार्ड डिस्क के किस सटीक भौतिक क्षेत्र (physical sector) पर स्थित होना अनिवार्य है?",opts:["CHS 0,0,1","CHS 1,0,0","CHS 0,1,0","CHS 1,1,1"],ans:0,exp:"मास्टर बूट रिकॉर्ड (MBR) संरचनात्मक रूप से हार्ड डिस्क ड्राइव के पहले भौतिक सेक्टर में स्थित होता है, जिसे क्लासिकल डिस्क ज्यामिति में सिलेंडर 0, हेड 0 और सेक्टर 1 (CHS 0,0,1) के रूप में दर्शाया जाता है।"}},
{type:"mcq",diff:"medium",en:{q:"According to traditional MBR architecture limits, what is the absolute maximum number of Primary Partitions that can be specified in the partition table?",opts:["4","3","2","5"],ans:0,exp:"Because of the compact 512-byte structural limitation of the Master Boot Record, the embedded partition table has exactly enough allocated space to define a maximum of four distinct Primary Partitions on a single disk."},hi:{q:"पारंपरिक MBR आर्किटेक्चर सीमाओं के अनुसार, पार्टीशन टेबल में निर्दिष्ट की जा सकने वाली प्राथमिक विभाजनों (Primary Partitions) की पूर्ण अधिकतम संख्या क्या है?",opts:["4","3","2","5"],ans:0,exp:"मास्टर बूट रिकॉर्ड की 512-बाइट संरचनात्मक सीमा के कारण, एम्बेडेड पार्टीशन टेबल में एक डिस्क पर अधिकतम चार अलग-अलग प्राथमिक विभाजनों को परिभाषित करने के लिए पर्याप्त आवंटित स्थान होता है।"}},
{type:"mcq",diff:"medium",en:{q:"In older Windows operating systems, which text-based boot file inherently contains the configuration parameters and menu choices for NTLDR?",opts:["Boot.ini","NTLDR.cfg","Bootmgr.ini","System.ini"],ans:0,exp:"The Boot.ini file is a simple but critical text file that contains the boot configuration options. Because the OS kernel isn't fully loaded, NTLDR explicitly reads Boot.ini to parse arguments and display the OS selection menu."},hi:{q:"पुराने विंडोज ऑपरेटिंग सिस्टम में, किस टेक्स्ट-आधारित बूट फ़ाइल में NTLDR के लिए कॉन्फ़िगरेशन पैरामीटर और मेनू विकल्प होते हैं?",opts:["Boot.ini","NTLDR.cfg","Bootmgr.ini","System.ini"],ans:0,exp:"Boot.ini फ़ाइल एक सरल लेकिन महत्वपूर्ण टेक्स्ट फ़ाइल है जिसमें बूट कॉन्फ़िगरेशन विकल्प होते हैं। NTLDR तर्कों को पार्स करने और OS चयन मेनू प्रदर्शित करने के लिए स्पष्ट रूप से Boot.ini को पढ़ता है।"}},
{type:"mcq",diff:"medium",en:{q:"What specific critical role does NTDETECT.COM fulfill during the standard Windows booting sequence?",opts:["It detects basic hardware and passes that information sequentially to NTLDR","It strictly loads the Windows NT kernel into memory","It exhaustively checks the RAM for parity errors","It directly configures and flashes the motherboard BIOS"],ans:0,exp:"During the Windows boot phase, NTDETECT.COM executes immediately after OS selection. Its sole critical role is to detect installed basic hardware components and faithfully pass this hardware profile information directly back to NTLDR."},hi:{q:"मानक विंडोज बूटिंग अनुक्रम के दौरान NTDETECT.COM कौन सी विशिष्ट महत्वपूर्ण भूमिका निभाता है?",opts:["यह बुनियादी हार्डवेयर का पता लगाता है और उस जानकारी को क्रमिक रूप से NTLDR को पास करता है","यह विंडोज एनटी कर्नेल को मेमोरी में लोड करता है","यह रैम की त्रुटियों के लिए विस्तृत रूप से जाँच करता है","यह मदरबोर्ड BIOS को सीधे कॉन्फ़िगर करता है"],ans:0,exp:"विंडोज बूट चरण के दौरान, NTDETECT.COM OS चयन के तुरंत बाद निष्पादित होता है। इसकी एकमात्र महत्वपूर्ण भूमिका स्थापित बुनियादी हार्डवेयर घटकों का पता लगाना और इस जानकारी को सीधे NTLDR को पास करना है।"}},
{type:"mcq",diff:"medium",en:{q:"In classic Windows architecture, what is the explicit executable name of the Stage 2 boot loader that actively loads the kernel?",opts:["NTLDR","GRUB","LILO","BOOTMGR"],ans:0,exp:"NTLDR (NT Loader) serves architecturally as the stage 2 boot loader for older Windows NT-based systems (like XP). It securely resides in the active partition, parses boot.ini, and is responsible for subsequently loading the Windows kernel."},hi:{q:"क्लासिक विंडोज वास्तुकला में, स्टेज 2 बूट लोडर का स्पष्ट निष्पादन योग्य नाम (executable name) क्या है जो सक्रिय रूप से कर्नेल को लोड करता है?",opts:["NTLDR","GRUB","LILO","BOOTMGR"],ans:0,exp:"NTLDR (NT Loader) पुराने Windows NT-आधारित सिस्टम (जैसे XP) के लिए स्टेज 2 बूट लोडर के रूप में कार्य करता है। यह सक्रिय पार्टीशन में सुरक्षित रूप से रहता है, boot.ini को पार्स करता है, और विंडोज कर्नेल को लोड करता है।"}},
{type:"mcq",diff:"medium",en:{q:"A classic Floppy Disk Drive interfaces with the motherboard utilizing a specialized ribbon cable comprising how many pins?",opts:["34-pin","40-pin","80-pin","20-pin"],ans:0,exp:"A floppy disk drive connects to the motherboard's dedicated floppy controller via a highly specific 34-pin ribbon cable, distinguishing it visually and physically from standard 40-pin IDE hard drive ribbon cables."},hi:{q:"एक क्लासिक फ्लॉपी डिस्क ड्राइव मदरबोर्ड के साथ एक विशेष रिबन केबल का उपयोग करके जुड़ता है जिसमें कितने पिन होते हैं?",opts:["34-पिन","40-पिन","80-पिन","20-पिन"],ans:0,exp:"फ्लॉपी डिस्क ड्राइव मदरबोर्ड के समर्पित फ्लॉपी कंट्रोलर से एक अत्यधिक विशिष्ट 34-पिन रिबन केबल के माध्यम से जुड़ता है, जो इसे मानक 40-पिन IDE हार्ड ड्राइव रिबन केबलों से अलग करता है।"}},
{type:"mcq",diff:"medium",en:{q:"The universally color-coded green PS/2 port on a motherboard's rear panel is strictly intended to connect to which peripheral?",opts:["Mouse","Keyboard","Printer","Monitor"],ans:0,exp:"To prevent hazardous user error when blindly plugging in peripherals, PS/2 ports conform to a rigorous color-coding standard. The green port is exclusively for the mouse, whereas the purple is reserved solely for the keyboard."},hi:{q:"मदरबोर्ड के रियर पैनल पर सार्वभौमिक रूप से रंग-कोडित हरा PS/2 पोर्ट सख्ती से किस परिधीय (peripheral) से जुड़ने के लिए होता है?",opts:["माउस","कीबोर्ड","प्रिंटर","मॉनिटर"],ans:0,exp:"उपकरणों को प्लग करते समय उपयोगकर्ता की त्रुटि को रोकने के लिए, PS/2 पोर्ट एक कठोर रंग-कोडिंग मानक के अनुरूप होते हैं। हरा पोर्ट विशेष रूप से माउस के लिए होता है, जबकि बैंगनी कीबोर्ड के लिए आरक्षित होता है।"}},
{type:"mcq",diff:"medium",en:{q:"Within the CPU's complex architecture, which functional block extracts instructions from memory, effectively decodes them, and oversees their execution?",opts:["Control Unit (CU)","Arithmetic Logic Unit (ALU)","Internal Registers","L1 Cache Memory"],ans:0,exp:"The Control Unit (CU) is the primary directive component of the CPU. It systematically fetches program instructions from main memory, logically decodes them, and strictly coordinates with the ALU and other units to execute them."},hi:{q:"सीपीयू की जटिल वास्तुकला के भीतर, कौन सा कार्यात्मक ब्लॉक मेमोरी से निर्देश निकालता है, उन्हें प्रभावी ढंग से डिकोड करता है, और उनके निष्पादन की देखरेख करता है?",opts:["कंट्रोल यूनिट (CU)","अर्थमैटिक लॉजिक यूनिट (ALU)","आंतरिक रजिस्टर","L1 कैश मेमोरी"],ans:0,exp:"कंट्रोल यूनिट (CU) सीपीयू का प्राथमिक निर्देशक घटक है। यह व्यवस्थित रूप से मुख्य मेमोरी से प्रोग्राम निर्देश लाता है, उन्हें तार्किक रूप से डिकोड करता है, और उन्हें निष्पादित करने के लिए ALU के साथ समन्वय करता है।"}},
{type:"mcq",diff:"medium",en:{q:"Which of the following serves as the highly volatile, temporary data storage workspace exclusively utilized while the CPU actively processes instructions?",opts:["Random Access Memory (RAM)","Internal Hard Disk Drive","Read Only Memory (ROM)","Optical CD-ROM Media"],ans:0,exp:"RAM functions as the computer's indispensable volatile workspace. When programs are launched, they are transferred from the slow hard disk into high-speed RAM, allowing the CPU to instantly access and manipulate real-time operational data."},hi:{q:"निम्नलिखित में से कौन सा उच्च वाष्पशील (volatile), अस्थायी डेटा भंडारण कार्यक्षेत्र के रूप में कार्य करता है जिसका उपयोग सीपीयू निर्देशों को संसाधित करते समय करता है?",opts:["रैंडम एक्सेस मेमोरी (RAM)","आंतरिक हार्ड डिस्क ड्राइव","रीड ओनली मेमोरी (ROM)","ऑप्टिकल CD-ROM मीडिया"],ans:0,exp:"RAM कंप्यूटर के अपरिहार्य वाष्पशील कार्यक्षेत्र के रूप में कार्य करता है। जब प्रोग्राम लॉन्च किए जाते हैं, तो उन्हें धीमी हार्ड डिस्क से हाई-स्पीड रैम में स्थानांतरित किया जाता है, जिससे CPU रीयल-टाइम डेटा तक पहुंच सकता है।"}},
{type:"mcq",diff:"medium",en:{q:"During the intricate Windows OS boot progression, which specific file dynamically generates a unique hardware key after every system reboot?",opts:["NTDETECT.COM","NTLDR","Boot.ini","System BIOS"],ans:0,exp:"NTDETECT.COM actively audits the machine's base hardware upon every individual reboot. Using this freshly polled diagnostic data, NTLDR dynamically generates a specific hardware key injected directly into the Windows Registry to configure drivers."},hi:{q:"विंडोज OS बूट प्रगति के दौरान, कौन सी विशिष्ट फ़ाइल हर सिस्टम रिबूट के बाद गतिशील रूप से एक अद्वितीय हार्डवेयर कुंजी (hardware key) उत्पन्न करती है?",opts:["NTDETECT.COM","NTLDR","Boot.ini","System BIOS"],ans:0,exp:"NTDETECT.COM हर व्यक्तिगत रिबूट पर मशीन के बेस हार्डवेयर का सक्रिय रूप से ऑडिट करता है। इस डेटा का उपयोग करके, NTLDR ड्राइवरों को कॉन्फ़िगर करने के लिए एक विशिष्ट हार्डवेयर कुंजी उत्पन्न करता है।"}},
{type:"tf",diff:"medium",en:{q:"According to hard disk formatting rules, an Extended Partition acts as a logical container that can be sub-divided into multiple smaller logical partitions.",opts:["True","False"],ans:0,exp:"Unlike primary partitions, an Extended Partition is not immediately formatted with a standard filesystem. Instead, it functions architecturally as a rigid container designed explicitly to house one or more logical drives."},hi:{q:"हार्ड डिस्क फ़ॉर्मेटिंग नियमों के अनुसार, एक विस्तारित विभाजन (Extended Partition) एक तार्किक कंटेनर के रूप में कार्य करता है जिसे कई छोटे तार्किक विभाजनों में उप-विभाजित किया जा सकता है।",opts:["सही","गलत"],ans:0,exp:"प्राथमिक विभाजनों के विपरीत, एक विस्तारित विभाजन को मानक फ़ाइल सिस्टम के साथ तुरंत स्वरूपित नहीं किया जाता है। इसके बजाय, यह एक या अधिक तार्किक ड्राइव रखने के लिए स्पष्ट रूप से डिज़ाइन किए गए एक कंटेनर के रूप में कार्य करता है।"}},
{type:"tf",diff:"medium",en:{q:"A primary operational restriction of Universal Serial Bus (USB) devices is that they stringently require a full system reboot whenever physically swapped.",opts:["True","False"],ans:1,exp:"This statement is entirely false. USB devices are inherently designed to be 'hot swappable,' meaning the operating system dynamically loads drivers, allowing them to be instantly attached or detached without disrupting system power or requiring reboots."},hi:{q:"यूनिवर्सल सीरियल बस (USB) उपकरणों का एक प्राथमिक परिचालन प्रतिबंध यह है कि जब भी उन्हें भौतिक रूप से बदला जाता है तो उन्हें पूर्ण सिस्टम रिबूट की सख्त आवश्यकता होती है।",opts:["सही","गलत"],ans:1,exp:"यह कथन पूरी तरह से गलत है। USB डिवाइस 'हॉट स्वैपेबल' होने के लिए डिज़ाइन किए गए हैं, जिसका अर्थ है कि ऑपरेटिंग सिस्टम गतिशील रूप से ड्राइवर लोड करता है, जिससे उन्हें बिना सिस्टम को पुनरारंभ किए जोड़ा या हटाया जा सकता है।"}},
{type:"mcq",diff:"hard",en:{q:"In Charles Babbage's revolutionary Analytical Engine design from 1833, the component designated as the 'mill' functionally correlates to which modern computer architecture sub-system?",opts:["Central Processing Unit (CPU)","Volatile Storage Memory (RAM)","Input Punch Card Reader","Hard Copy Printer Output"],ans:0,exp:"Babbage’s visionary Analytical Engine architecture segmented operations strictly. The 'mill' was explicitly designed as the arithmetic and logic execution section performing complex calculations, making it the direct conceptual predecessor to the modern CPU."},hi:{q:"1833 के चार्ल्स बैबेज के क्रांतिकारी एनालिटिकल इंजन डिजाइन में, 'मिल' (mill) के रूप में नामित घटक कार्यात्मक रूप से किस आधुनिक कंप्यूटर आर्किटेक्चर सब-सिस्टम से संबंधित है?",opts:["सेंट्रल प्रोसेसिंग यूनिट (CPU)","वोलेटाइल स्टोरेज मेमोरी (RAM)","इनपुट पंच कार्ड रीडर","हार्ड कॉपी प्रिंटर आउटपुट"],ans:0,exp:"बैबेज की एनालिटिकल इंजन वास्तुकला ने संचालन को सख्ती से विभाजित किया था। 'मिल' को स्पष्ट रूप से जटिल गणना करने वाले अंकगणित और तर्क निष्पादन अनुभाग के रूप में डिज़ाइन किया गया था, जो इसे आधुनिक CPU का वैचारिक पूर्ववर्ती बनाता है।"}},
{type:"mcq",diff:"hard",en:{q:"What was the staggering documented baseline electrical power requirement necessary to continuously operate the massive ENIAC first-generation vacuum tube computer?",opts:["150,000 watts","50,000 watts","100,000 watts","200,000 watts"],ans:0,exp:"The ENIAC was a colossal physical undertaking. Structurally incorporating roughly 18,000 fragile vacuum tubes, 70,000 resistors, and weighing 30 tons, it demanded a staggering 150,000 watts of raw electricity just to operate fundamentally."},hi:{q:"विशाल ENIAC पहली पीढ़ी के वैक्यूम ट्यूब कंप्यूटर को लगातार संचालित करने के लिए आवश्यक आधारभूत विद्युत शक्ति (electrical power requirement) कितनी थी?",opts:["150,000 वाट","50,000 वाट","100,000 वाट","200,000 वाट"],ans:0,exp:"ENIAC एक विशाल भौतिक उपक्रम था। लगभग 18,000 नाजुक वैक्यूम ट्यूब, 70,000 रेसिस्टर्स को शामिल करते हुए और 30 टन वजन के साथ, इसे संचालित करने के लिए 150,000 वाट बिजली की मांग थी।"}},
{type:"mcq",diff:"hard",en:{q:"While transistors aggressively replaced vacuum tubes for CPU logic in second-generation computing, what advanced technology was primarily adopted for high-speed main memory?",opts:["Ferrite cores","Vacuum tube delay lines","Sequential magnetic tapes","Semiconductor chips"],ans:0,exp:"Although transistors revolutionized second-generation CPU processing by replacing tubes, main memory concurrently evolved. Engineers transitioned from slow acoustical lines to utilizing microscopic, magnetically polarized magnetic ferrite cores for reliable, high-speed main memory."},hi:{q:"दूसरी पीढ़ी की कंप्यूटिंग में सीपीयू लॉजिक के लिए वैक्यूम ट्यूबों की जगह ट्रांजिस्टर ने ले ली, लेकिन हाई-स्पीड मुख्य मेमोरी (main memory) के लिए मुख्य रूप से किस उन्नत तकनीक को अपनाया गया था?",opts:["फेराइट कोर (Ferrite cores)","वैक्यूम ट्यूब डिले लाइन्स","अनुक्रमिक चुंबकीय टेप","अर्धचालक चिप्स"],ans:0,exp:"हालांकि ट्रांजिस्टर ने दूसरी पीढ़ी के सीपीयू प्रसंस्करण में क्रांति ला दी, मुख्य मेमोरी एक साथ विकसित हुई। इंजीनियरों ने विश्वसनीय, उच्च गति वाली मुख्य मेमोरी के लिए चुंबकीय रूप से ध्रुवीकृत चुंबकीय फेराइट कोर का उपयोग करने के लिए संक्रमण किया।"}},
{type:"mcq",diff:"hard",en:{q:"Which revolutionary processing component breakthrough directly catalyzed the transition from second-generation to third-generation computing architectures?",opts:["Small and medium scale Integrated Circuits (ICs)","Very Large Scale Integration (VLSI) chips","Mass deployment of discreet Transistors","Re-introduction of miniaturized Vacuum tubes"],ans:0,exp:"The seminal defining characteristic of third-generation computers was the profound invention and deployment of Integrated Circuits (ICs). These dense chips packed the capability of roughly 300 discrete transistors onto a single, highly-efficient silicon slice."},hi:{q:"किस क्रांतिकारी प्रसंस्करण घटक सफलता ने सीधे दूसरी पीढ़ी से तीसरी पीढ़ी के कंप्यूटिंग आर्किटेक्चर में संक्रमण को उत्प्रेरित किया?",opts:["छोटे और मध्यम पैमाने के इंटीग्रेटेड सर्किट (IC)","वेरी लार्ज स्केल इंटीग्रेशन (VLSI) चिप्स","असतत ट्रांजिस्टर की बड़े पैमाने पर तैनाती","लघु वैक्यूम ट्यूबों का पुन: परिचय"],ans:0,exp:"तीसरी पीढ़ी के कंप्यूटरों की प्रारंभिक परिभाषित विशेषता इंटीग्रेटेड सर्किट्स (ICs) का आविष्कार थी। इन चिप्स ने लगभग 300 असतत ट्रांजिस्टरों की क्षमता को एक ही अत्यधिक कुशल सिलिकॉन स्लाइस पर पैक कर दिया था।"}},
{type:"mcq",diff:"hard",en:{q:"In defining modern fourth-generation computer architecture, what physically acts as the foundational main switching element inside a microcomputer?",opts:["VLSI Microprocessor","Discrete LSI IC arrays","Experimental ULSI Bio-chips","Standalone planar Transistors"],ans:0,exp:"Fourth-generation microcomputers fundamentally rely on Very Large Scale Integration (VLSI) technology. This dense miniaturization allows the entire intricate CPU, traditionally spanning multiple boards, to be elegantly condensed onto a single, incredibly complex microprocessor chip."},hi:{q:"आधुनिक चौथी पीढ़ी के कंप्यूटर वास्तुकला को परिभाषित करने में, एक माइक्रो कंप्यूटर के अंदर मूलभूत मुख्य स्विचिंग तत्व के रूप में भौतिक रूप से क्या कार्य करता है?",opts:["VLSI माइक्रोप्रोसेसर","असतत LSI IC सरणियाँ","प्रायोगिक ULSI बायो-चिप्स","स्टैंडअलोन प्लानर ट्रांजिस्टर"],ans:0,exp:"चौथी पीढ़ी के माइक्रो कंप्यूटर मुख्य रूप से वेरी लार्ज स्केल इंटीग्रेशन (VLSI) तकनीक पर निर्भर करते हैं। यह लघुकरण संपूर्ण जटिल CPU को एकल, अविश्वसनीय रूप से जटिल माइक्रोप्रोसेसर चिप पर संघनित करने की अनुमति देता है।"}},
{type:"mcq",diff:"hard",en:{q:"Which highly specific computer classification is heavily favored to function as a robust, centralized multi-user store of corporate information exclusively for small and medium-sized enterprises?",opts:["Mini computer","Mainframe computer","Standalone Microcomputer","Cray Supercomputer"],ans:0,exp:"Minicomputers fit perfectly into a distinct mid-range performance tier. They are significantly more robust than basic PCs, executing millions of instructions for up to 4000 concurrent terminal users, making them ideal centralized hubs for medium-sized corporations."},hi:{q:"छोटे और मध्यम आकार के उद्यमों के लिए विशेष रूप से कॉर्पोरेट जानकारी के मजबूत, केंद्रीकृत मल्टी-यूज़र स्टोर के रूप में कार्य करने के लिए किस अत्यधिक विशिष्ट कंप्यूटर वर्गीकरण को बहुत पसंद किया जाता है?",opts:["मिनी कंप्यूटर","मेनफ्रेम कंप्यूटर","स्टैंडअलोन माइक्रो कंप्यूटर","क्रे (Cray) सुपरकंप्यूटर"],ans:0,exp:"मिनीकंप्यूटर (Minicomputers) एक अलग मिड-रेंज परफॉर्मेंस टियर में पूरी तरह से फिट होते हैं। वे बुनियादी पीसी की तुलना में काफी अधिक मजबूत हैं, जो 4000 समवर्ती टर्मिनल उपयोगकर्ताओं के लिए काम करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Structurally analyzing the first physical sector of a bootable hard drive, what is the exact, unvarying byte size of the Master Boot Record (MBR)?",opts:["512 bytes","256 bytes","1024 bytes","2048 bytes"],ans:0,exp:"The MBR is incredibly compact yet vital. Standardized historically across legacy PC architectures, the MBR rigorously occupies exactly 512 bytes of space. Within this tiny footprint, it strictly houses the bootstrap loader code and the primary partition table."},hi:{q:"बूट करने योग्य हार्ड ड्राइव के पहले भौतिक सेक्टर का संरचनात्मक रूप से विश्लेषण करने पर, मास्टर बूट रिकॉर्ड (MBR) का सटीक, अपरिवर्तनीय बाइट आकार क्या है?",opts:["512 बाइट्स","256 बाइट्स","1024 बाइट्स","2048 बाइट्स"],ans:0,exp:"MBR अविश्वसनीय रूप से कॉम्पैक्ट लेकिन महत्वपूर्ण है। लीगेसी पीसी आर्किटेक्चर में ऐतिहासिक रूप से मानकीकृत, MBR ठीक 512 बाइट्स स्थान घेरता है। इस छोटे से पदचिह्न के भीतर, इसमें बूटस्ट्रैप लोडर कोड और प्राथमिक विभाजन तालिका होती है।"}},
{type:"mcq",diff:"hard",en:{q:"When mapping physical hard disk geometry, the MBR is fundamentally located at CHS 0,0,1. What precisely does the acronym CHS articulate?",opts:["Cylinder, Head, Sector","Cluster, Head, Sector","Cylinder, Hard disk, Sector","Cluster, Hard drive, Sector"],ans:0,exp:"In classic hard disk geometry addressing, CHS precisely denotes Cylinder, Head, and Sector. The very first physical data block on any platter surface is strictly targeted by addressing the 0th Cylinder, 0th Head, and the 1st Sector (CHS 0,0,1)."},hi:{q:"भौतिक हार्ड डिस्क ज्यामिति की मैपिंग करते समय, MBR मूल रूप से CHS 0,0,1 पर स्थित होता है। CHS संक्षिप्त नाम का सटीक अर्थ क्या है?",opts:["सिलेंडर, हेड, सेक्टर (Cylinder, Head, Sector)","क्लस्टर, हेड, सेक्टर","सिलेंडर, हार्ड डिस्क, सेक्टर","क्लस्टर, हार्ड ड्राइव, सेक्टर"],ans:0,exp:"क्लासिक हार्ड डिस्क ज्यामिति एड्रेसिंग में, CHS ठीक सिलेंडर, हेड और सेक्टर को दर्शाता है। किसी भी प्लैटर सतह पर सबसे पहला भौतिक डेटा ब्लॉक 0वें सिलेंडर, 0वें हेड और 1ले सेक्टर (CHS 0,0,1) द्वारा सख्ती से लक्षित किया जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"Given the rigid limitations of a standard MBR partition table which contains exactly 3 defined Primary Partitions, what is the absolute maximum number of Extended Partitions allowed?",opts:["1","2","3","0"],ans:0,exp:"An MBR partition table is structurally restricted to a maximum of four total partition entries. Therefore, if three entries are explicitly consumed by Primary Partitions, only exactly one remaining slot can legally be assigned as an Extended Partition."},hi:{q:"मानक MBR पार्टीशन टेबल की कठोर सीमाओं को देखते हुए, जिसमें ठीक 3 परिभाषित प्राथमिक पार्टीशन (Primary Partitions) हैं, अनुमत विस्तारित पार्टीशन (Extended Partitions) की पूर्ण अधिकतम संख्या क्या है?",opts:["1","2","3","0"],ans:0,exp:"एक MBR पार्टीशन टेबल संरचनात्मक रूप से कुल चार पार्टीशन प्रविष्टियों तक सीमित है। इसलिए, यदि तीन प्रविष्टियां स्पष्ट रूप से प्राथमिक विभाजनों द्वारा उपभोग की जाती हैं, तो केवल एक शेष स्लॉट को कानूनी रूप से विस्तारित विभाजन के रूप में असाइन किया जा सकता है।"}},
{type:"mcq",diff:"hard",en:{q:"Architecturally, what explicit name is given to the logical first 512-byte sector residing precisely at the start of any active Primary Partition?",opts:["Partition Boot Sector (PBR)","Extended Boot Sector (EBR)","Master Boot Record (MBR)","Logical Boot Sector (LBR)"],ans:0,exp:"The logical first sector physically mapped at the beginning of a formatted Primary Partition is known as the Partition Boot Sector (PBR). It contains the vital, OS-specific volume boot code required to seamlessly initialize and execute OS files."},hi:{q:"वास्तुशिल्प रूप से (architecturally), किसी भी सक्रिय प्राथमिक विभाजन के ठीक शुरुआत में रहने वाले तार्किक प्रथम 512-बाइट सेक्टर को क्या स्पष्ट नाम दिया गया है?",opts:["विभाजन बूट सेक्टर (PBR)","विस्तारित बूट सेक्टर (EBR)","मास्टर बूट रिकॉर्ड (MBR)","लॉजिकल बूट सेक्टर (LBR)"],ans:0,exp:"फ़ॉर्मेट किए गए प्राथमिक विभाजन की शुरुआत में भौतिक रूप से मैप किए गए तार्किक पहले सेक्टर को पार्टीशन बूट सेक्टर (PBR) के रूप में जाना जाता है। इसमें ओएस फ़ाइलों को मूल रूप से आरंभ करने के लिए आवश्यक बूट कोड होता है।"}},
{type:"mcq",diff:"hard",en:{q:"In older NT-based Windows Operating Systems, what is the exact, canonical default directory path pointing to the NTLDR stage 2 boot loader file?",opts:["C:\\Windows\\i386\\NTLDR","C:\\System32\\NTLDR","C:\\Boot\\NTLDR","C:\\NTLDR"],ans:0,exp:"In legacy Windows NT architectures, NTLDR is the highly crucial stage 2 boot loader responsible for passing control to the kernel. According to canonical Microsoft paths documented, it resides securely within the C:\\Windows\\i386\\NTLDR directory structure."},hi:{q:"पुराने NT-आधारित विंडोज ऑपरेटिंग सिस्टम में, NTLDR चरण 2 बूट लोडर फ़ाइल की ओर इशारा करने वाला सटीक डिफ़ॉल्ट निर्देशिका पथ (directory path) क्या है?",opts:["C:\\Windows\\i386\\NTLDR","C:\\System32\\NTLDR","C:\\Boot\\NTLDR","C:\\NTLDR"],ans:0,exp:"विरासत (legacy) Windows NT आर्किटेक्चर में, NTLDR अत्यधिक महत्वपूर्ण स्टेज 2 बूट लोडर है जो कर्नेल को नियंत्रण पास करने के लिए जिम्मेदार है। यह C:\\Windows\\i386\\NTLDR निर्देशिका संरचना के भीतर सुरक्षित रूप से रहता है।"}},
{type:"mcq",diff:"hard",en:{q:"After NTDETECT.COM rigorously scans the physical hardware, it generates unique hardware configuration keys. Where are these keys explicitly injected into the Windows Registry?",opts:["HKEY_LOCAL_MACHINE\\HARDWARE","HKEY_CURRENT_USER\\HARDWARE","HKEY_CLASSES_ROOT\\SYSTEM","HKEY_USERS\\HARDWARE"],ans:0,exp:"Following its exhaustive hardware polling sequence, NTDETECT.COM explicitly passes the generated hardware profile directly to NTLDR. NTLDR then systematically writes this volatile hardware key data directly into the HKEY_LOCAL_MACHINE\\HARDWARE registry hive."},hi:{q:"NTDETECT.COM द्वारा भौतिक हार्डवेयर को सख्ती से स्कैन करने के बाद, यह अद्वितीय हार्डवेयर कॉन्फ़िगरेशन कुंजियाँ (keys) उत्पन्न करता है। ये कुंजियाँ स्पष्ट रूप से विंडोज रजिस्ट्री में कहाँ इंजेक्ट की जाती हैं?",opts:["HKEY_LOCAL_MACHINE\\HARDWARE","HKEY_CURRENT_USER\\HARDWARE","HKEY_CLASSES_ROOT\\SYSTEM","HKEY_USERS\\HARDWARE"],ans:0,exp:"अपने विस्तृत हार्डवेयर पोलिंग अनुक्रम के बाद, NTDETECT.COM उत्पन्न हार्डवेयर प्रोफ़ाइल को सीधे NTLDR को पास करता है। NTLDR फिर इस डेटा को सीधे HKEY_LOCAL_MACHINE\\HARDWARE रजिस्ट्री हाइव में लिखता है।"}},
{type:"mcq",diff:"hard",en:{q:"Focusing on modern ATX motherboard power delivery standards, the principal main power connector explicitly bridging the SMPS to the motherboard comprises exactly how many pins?",opts:["20 pins","24 pins","16 pins","12 pins"],ans:0,exp:"While modern extended variants utilize 24 pins, the classical, standard ATX power supply connector, strictly defined for providing multiplexed DC voltages (+/-12V, +/-5V, 3.3V) directly to the motherboard, structurally consists of exactly 20 pins."},hi:{q:"आधुनिक ATX मदरबोर्ड पावर डिलीवरी मानकों पर ध्यान केंद्रित करते हुए, SMPS को मदरबोर्ड से जोड़ने वाले मुख्य पावर कनेक्टर में ठीक कितने पिन होते हैं?",opts:["20 पिन","24 पिन","16 पिन","12 पिन"],ans:0,exp:"जबकि आधुनिक विस्तारित वेरिएंट 24 पिन का उपयोग करते हैं, मदरबोर्ड को सीधे मल्टीप्लेक्स डीसी वोल्टेज (+/-12V, +/-5V, 3.3V) प्रदान करने के लिए कड़ाई से परिभाषित क्लासिकल, मानक ATX बिजली आपूर्ति कनेक्टर में संरचनात्मक रूप से ठीक 20 पिन होते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"In advanced PC motherboard terminology, what technical capability explicitly defines a 'PnP BIOS'?",opts:["A flash memory-based BIOS natively engineered to handle automated Plug-and-Play device assignments","A purely ROM-based BIOS that strictly manages all legacy peripheral configurations","A RAM-based BIOS overlay that shadows custom CMOS configuration tools","A peripheral-based BIOS installed directly on expansion cards"],ans:0,exp:"A PnP (Plug-and-Play) BIOS represents a significant architectural leap. Crucially implemented using rewritable flash memory rather than static ROM, it autonomously configures IRQs, DMA channels, and I/O addresses for newly attached Plug-and-Play hardware without user intervention."},hi:{q:"उन्नत पीसी मदरबोर्ड शब्दावली में, कौन सी तकनीकी क्षमता स्पष्ट रूप से 'PnP BIOS' को परिभाषित करती है?",opts:["स्वचालित प्लग-एंड-प्ले डिवाइस असाइनमेंट को संभालने के लिए मूल रूप से इंजीनियर किया गया फ्लैश मेमोरी-आधारित BIOS","एक विशुद्ध रूप से ROM-आधारित BIOS जो सभी पुराने परिधीय कॉन्फ़िगरेशन का सख्ती से प्रबंधन करता है","एक RAM-आधारित BIOS ओवरले जो कस्टम CMOS कॉन्फ़िगरेशन टूल को शैडो करता है","एक परिधीय-आधारित BIOS सीधे विस्तार कार्ड पर स्थापित किया गया"],ans:0,exp:"PnP (प्लग-एंड-प्ले) BIOS एक महत्वपूर्ण वास्तुकला छलांग का प्रतिनिधित्व करता है। स्थिर ROM के बजाय पुनर्लेखन योग्य फ्लैश मेमोरी का उपयोग करते हुए, यह उपयोगकर्ता के हस्तक्षेप के बिना नए जुड़े प्लग-एंड-प्ले हार्डवेयर के लिए स्वायत्त रूप से IRQ, DMA आदि कॉन्फ़िगर करता है।"}},
{type:"mcq",diff:"hard",en:{q:"Regarding historical PC expansion bus hierarchies, what does the acronym ISA explicitly stand for when referencing motherboard slots?",opts:["Industry Standard Architecture","Internal System Architecture","Integrated Standard Architecture","Industry System Array"],ans:0,exp:"ISA meticulously stands for Industry Standard Architecture. It was the paramount, albeit extremely slow, original 8-bit (later 16-bit) expansion bus standard natively utilized in early PC motherboards before being completely obsoleted and replaced by faster PCI slots."},hi:{q:"ऐतिहासिक पीसी एक्सपेंशन बस पदानुक्रम के संबंध में, मदरबोर्ड स्लॉट का संदर्भ देते समय ISA का संक्षिप्त नाम स्पष्ट रूप से क्या है?",opts:["इंडस्ट्री स्टैण्डर्ड आर्किटेक्चर (Industry Standard Architecture)","इंटरनल सिस्टम आर्किटेक्चर","इंटीग्रेटेड स्टैण्डर्ड आर्किटेक्चर","इंडस्ट्री सिस्टम एरे"],ans:0,exp:"ISA का विस्तृत अर्थ इंडस्ट्री स्टैण्डर्ड आर्किटेक्चर है। यह तेज़ पीसीआई (PCI) स्लॉट द्वारा पूरी तरह से अप्रचलित और प्रतिस्थापित किए जाने से पहले शुरुआती पीसी मदरबोर्ड में इस्तेमाल किया जाने वाला मूल 8-बिट (बाद में 16-बिट) विस्तार बस मानक था।"}},
{type:"mcq",diff:"hard",en:{q:"If a critical hardware fault is detected at the very lowest level during the Power-On Self-Test (POST), how does the raw BIOS predominantly halt and alert the technician?",opts:["By halting the process and emitting a specific sequence of audio beep sounds","By instantly displaying a detailed Blue Screen of Death (BSOD)","By aggressively blinking the front panel power LED indicator","By automatically attempting to reboot the system infinitely"],ans:0,exp:"Because a POST failure often implies that even the video output sub-system might be broken or uninitialized, the bare-metal BIOS is engineered to halt the boot process entirely and communicate diagnostic error codes via patterned auditory beep sounds."},hi:{q:"यदि पावर-ऑन सेल्फ-टेस्ट (POST) के दौरान सबसे निचले स्तर पर किसी महत्वपूर्ण हार्डवेयर दोष का पता चलता है, तो रॉ BIOS मुख्य रूप से तकनीशियन को कैसे रोकता है और सचेत करता है?",opts:["प्रक्रिया को रोककर और ऑडियो बीप ध्वनियों के एक विशिष्ट अनुक्रम का उत्सर्जन करके","तुरंत मृत्यु की विस्तृत नीली स्क्रीन (BSOD) प्रदर्शित करके","फ्रंट पैनल पावर एलईडी इंडिकेटर को आक्रामक रूप से ब्लिंक करके","सिस्टम को स्वचालित रूप से असीमित रूप से रिबूट करने का प्रयास करके"],ans:0,exp:"चूंकि POST विफलता का अर्थ अक्सर यह होता है कि वीडियो आउटपुट सब-सिस्टम भी टूट गया है, इसलिए बेयर-मेटल BIOS बूट प्रक्रिया को पूरी तरह से रोकने और पैटर्न वाली श्रवण बीप ध्वनियों के माध्यम से नैदानिक ​​त्रुटि कोड संचारित करने के लिए इंजीनियर किया गया है।"}},
{type:"mcq",diff:"hard",en:{q:"Reviewing the classical triplet of fundamental boot files required for launching an older Windows NT-based operating system, which of the following is strictly NOT a boot file?",opts:["KERNEL.EXE","NTLDR","Boot.ini","NTDETECT.COM"],ans:0,exp:"The Windows boot sequence is incredibly strict. NTLDR, Boot.ini, and NTDETECT.COM physically reside within the active partition as the foundational trio required to initialize the boot sequence. KERNEL.EXE is an invalid, fictitious artifact in this specific bootstrap context."},hi:{q:"पुराने विंडोज NT-आधारित ऑपरेटिंग सिस्टम को लॉन्च करने के लिए आवश्यक मौलिक बूट फ़ाइलों के क्लासिकल ट्रिपलेट की समीक्षा करते हुए, निम्नलिखित में से कौन सी बूट फ़ाइल नहीं है?",opts:["KERNEL.EXE","NTLDR","Boot.ini","NTDETECT.COM"],ans:0,exp:"विंडोज बूट अनुक्रम अविश्वसनीय रूप से सख्त है। NTLDR, Boot.ini, और NTDETECT.COM बूट अनुक्रम को आरंभ करने के लिए आवश्यक मूलभूत तिकड़ी के रूप में सक्रिय विभाजन के भीतर भौतिक रूप से रहते हैं। KERNEL.EXE इस संदर्भ में एक अमान्य फ़ाइल है।"}},
{type:"mcq",diff:"hard",en:{q:"Focusing on the physical mechanical layout of a typical ATX system unit chassis, what exact hardware components are the 5.25\" and 3.5\" Drive Bays precisely engineered to house?",opts:["Magnetic and optical storage devices like Hard Disk Drives and DVD/CD-ROMs","Oversized modular power supply units (SMPS)","Excessively long PCIe video expansion cards","Vertical inline system RAM memory modules"],ans:0,exp:"A computer chassis features specific, dimensionally standardized internal metal brackets known as Drive Bays. The 5.25-inch bays are historically reserved for housing larger optical drives (CD/DVD), while the 3.5-inch bays precisely mount internal magnetic Hard Disk Drives or Floppy drives."},hi:{q:"एक विशिष्ट ATX सिस्टम यूनिट चेसिस के भौतिक यांत्रिक लेआउट पर ध्यान केंद्रित करते हुए, 5.25\" और 3.5\" ड्राइव बे विशेष रूप से किन सटीक हार्डवेयर घटकों को रखने के लिए इंजीनियर किए गए हैं?",opts:["चुंबकीय और ऑप्टिकल भंडारण उपकरण जैसे हार्ड डिस्क ड्राइव और डीवीडी/सीडी-रोम","बड़े मॉड्यूलर बिजली आपूर्ति इकाइयां (SMPS)","अत्यधिक लंबे PCIe वीडियो विस्तार कार्ड","वर्टिकल इनलाइन सिस्टम रैम मेमोरी मॉड्यूल"],ans:0,exp:"कंप्यूटर चेसिस में विशिष्ट मानकीकृत आंतरिक धातु ब्रैकेट होते हैं जिन्हें ड्राइव बे के रूप में जाना जाता है। 5.25-इंच बे ऐतिहासिक रूप से बड़े ऑप्टिकल ड्राइव (CD/DVD) के लिए आरक्षित हैं, जबकि 3.5-इंच बे ठीक आंतरिक हार्ड डिस्क या फ्लॉपी ड्राइव को माउंट करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"In assessing massive-scale computational paradigms, what is the quintessential architectural difference separating a true Supercomputer from an enterprise Mainframe?",opts:["Supercomputers strictly channel overwhelming processing power to execute a single calculation as violently fast as possible, while mainframes distribute power to execute tens of thousands of smaller programs concurrently.","There is no tangible architectural difference; the terms are purely marketing buzzwords.","Mainframes intrinsically possess exponentially faster floating-point processing speeds than any Supercomputer.","Supercomputers are constrained strictly to business database processing, whereas mainframes excel entirely at scientific aerospace simulations."],ans:0,exp:"Supercomputers and mainframes have entirely divergent architectural philosophies. A supercomputer aggressively focuses thousands of processors tightly to solve one incredibly complex, massive mathematical problem instantly. Mainframes contrastingly optimize I/O and multitasking to process millions of smaller, disparate transactions concurrently."},hi:{q:"बड़े पैमाने के कम्प्यूटेशनल प्रतिमानों का आकलन करने में, एक सच्चे सुपरकंप्यूटर को एंटरप्राइज़ मेनफ्रेम से अलग करने वाला सर्वोत्कृष्ट वास्तुशिल्प अंतर क्या है?",opts:["सुपरकंप्यूटर एक ही गणना को तेजी से निष्पादित करने के लिए जबरदस्त प्रसंस्करण शक्ति को चैनलाइज़ करते हैं, जबकि मेनफ्रेम एक साथ हजारों छोटे प्रोग्रामों को निष्पादित करने के लिए शक्ति वितरित करते हैं।","कोई वास्तुकला अंतर नहीं है; शर्तें विशुद्ध रूप से विपणन चर्चा के शब्द हैं।","सुपरकंप्यूटर की तुलना में मेनफ्रेम में तेजी से फ्लोटिंग-पॉइंट प्रोसेसिंग गति होती है।","सुपरकंप्यूटर कड़ाई से व्यावसायिक डेटाबेस प्रसंस्करण तक ही सीमित हैं, जबकि मेनफ्रेम वैज्ञानिक सिमुलेशन में उत्कृष्टता प्राप्त करते हैं।"],ans:0,exp:"सुपरकंप्यूटर एक अविश्वसनीय रूप से जटिल, विशाल गणितीय समस्या को तुरंत हल करने के लिए हजारों प्रोसेसरों को सख्ती से केंद्रित करता है। इसके विपरीत, मेनफ्रेम एक साथ लाखों छोटे, अलग-अलग लेनदेन को संसाधित करने के लिए मल्टीटास्किंग का अनुकूलन करते हैं।"}},
{type:"mcq",diff:"hard",en:{q:"Historically, the pioneering electro-mechanical computer designated formally as the IBM Automatic Sequence Controlled Calculator (ASCC) is much more famously recognized worldwide by what alternative name?",opts:["Mark I","ENIAC","EDVAC","UNIVAC-1"],ans:0,exp:"Developed extensively at Harvard University in 1944, the massive electro-mechanical ASCC was famously re-christened as the Harvard Mark I. It stands as a monumental engineering milestone, recognized as the very first machine capable of executing long sequential arithmetic equations completely automatically."},hi:{q:"ऐतिहासिक रूप से, आईबीएम ऑटोमैटिक सीक्वेंस कंट्रोल्ड कैलकुलेटर (ASCC) के रूप में औपचारिक रूप से नामित अग्रणी इलेक्ट्रो-मैकेनिकल कंप्यूटर दुनिया भर में किस वैकल्पिक नाम से अधिक प्रसिद्ध है?",opts:["मार्क I (Mark I)","ENIAC","EDVAC","UNIVAC-1"],ans:0,exp:"1944 में हार्वर्ड विश्वविद्यालय में बड़े पैमाने पर विकसित, विशाल इलेक्ट्रो-मैकेनिकल ASCC को प्रसिद्ध रूप से हार्वर्ड मार्क I (Mark I) के रूप में फिर से नाम दिया गया था। यह पूरी तरह से स्वचालित रूप से लंबी अनुक्रमिक अंकगणितीय समीकरणों को निष्पादित करने में सक्षम पहली मशीन थी।"}},
{type:"mcq",diff:"hard",en:{q:"In computer science evolution, the seminal EDVAC architecture decisively broke away from prior designs by successfully introducing which revolutionary foundational concept?",opts:["Storing both data and executable program instructions intimately inside the computer's internal memory","Eradicating fragile vacuum tubes entirely in favor of microscopic semiconductor transistors","Inventing the Graphical User Interface (GUI) linked with a mechanical mouse","Introducing dynamic object-oriented high-level languages like C++ directly into hardware"],ans:0,exp:"The EDVAC (Electronic Discrete Variable Automatic Computer) drastically altered computing theory circa 1950 by practically introducing the 'stored-program' concept. By storing both execution instructions and operational data rapidly inside binary memory, it utterly eliminated the profound bottleneck of manual human rewiring between tasks."},hi:{q:"कंप्यूटर विज्ञान के विकास में, EDVAC वास्तुकला ने किस क्रांतिकारी मूलभूत अवधारणा को सफलतापूर्वक पेश करके पूर्व डिज़ाइनों से निर्णायक रूप से अलग हो गया?",opts:["डेटा और निष्पादन योग्य प्रोग्राम निर्देशों दोनों को कंप्यूटर की आंतरिक मेमोरी के अंदर स्टोर करना","माइक्रोस्कोपिक सेमीकंडक्टर ट्रांजिस्टर के पक्ष में नाजुक वैक्यूम ट्यूबों को पूरी तरह से मिटाना","मैकेनिकल माउस से जुड़े ग्राफिकल यूजर इंटरफेस (GUI) का आविष्कार","सी++ (C++) जैसी गतिशील ऑब्जेक्ट-ओरिएंटेड उच्च-स्तरीय भाषाओं को सीधे हार्डवेयर में पेश करना"],ans:0,exp:"EDVAC ने 1950 के आसपास 'स्टोर्ड-प्रोग्राम' अवधारणा को व्यावहारिक रूप से पेश करके कंप्यूटिंग सिद्धांत को काफी हद तक बदल दिया। निष्पादन निर्देशों और परिचालन डेटा दोनों को बाइनरी मेमोरी के अंदर तेजी से संग्रहीत करके, इसने बहुत बड़ी बाधाओं को पूरी तरह से समाप्त कर दिया।"}},
{type:"mcq",diff:"hard",en:{q:"When analyzing the performance metrics of the pioneering EDSAC stored-program computer, its raw operational processing speed natively fell into which highly specific temporal range?",opts:["Three millisecond range","Three microsecond range","Three nanosecond range","Three second range"],ans:0,exp:"The EDSAC (Electronic Delay Storage Automatic Computer), deployed effectively in 1949, was exceptionally fast for its primitive era but unfathomably slow today. Historically, its raw computational executions were accurately measured in the three millisecond range."},hi:{q:"अग्रणी EDSAC संग्रहित-प्रोग्राम कंप्यूटर के प्रदर्शन मेट्रिक्स का विश्लेषण करते समय, इसकी कच्ची परिचालन प्रसंस्करण गति (raw operational processing speed) मूल रूप से किस अत्यधिक विशिष्ट अस्थायी सीमा में आती है?",opts:["तीन मिलीसेकंड (Three millisecond) की सीमा","तीन माइक्रोसेकंड (Three microsecond) की सीमा","तीन नैनोसेकंड (Three nanosecond) की सीमा","तीन सेकंड (Three second) की सीमा"],ans:0,exp:"EDSAC (इलेक्ट्रॉनिक डिले स्टोरेज ऑटोमैटिक कंप्यूटर), जो 1949 में प्रभावी रूप से तैनात किया गया था, अपने आदिम युग के लिए असाधारण रूप से तेज़ था। ऐतिहासिक रूप से, इसके कच्चे कम्प्यूटेशनल निष्पादन को सटीक रूप से तीन मिलीसेकंड (three millisecond) की सीमा में मापा गया था।"}},
{type:"mcq",diff:"hard",en:{q:"Chronologically mapping the evolution of internal processor architectures, the development and mass deployment of intricate 64-bit microprocessors is officially attributed to which categorical generation of computers?",opts:["Fifth Generation","Fourth Generation","Third Generation","Second Generation"],ans:0,exp:"While the 4th generation pioneered the foundational microprocessor, the true 5th generation (present to future) explicitly boasts the advent of Ultra-Large Scale Integration (ULSI) and the complex architectural deployment of high-capacity 64-bit microprocessors managing immense memory spaces."},hi:{q:"आंतरिक प्रोसेसर आर्किटेक्चर के विकास को कालानुक्रमिक रूप से मैप करते हुए, जटिल 64-बिट माइक्रोप्रोसेसरों के विकास और बड़े पैमाने पर तैनाती का श्रेय आधिकारिक तौर पर कंप्यूटर की किस पीढ़ी को दिया जाता है?",opts:["पांचवीं पीढ़ी (Fifth Generation)","चौथी पीढ़ी","तीसरी पीढ़ी","दूसरी पीढ़ी"],ans:0,exp:"जबकि चौथी पीढ़ी ने मूलभूत माइक्रोप्रोसेसर का बीड़ा उठाया, सच्ची 5वीं पीढ़ी अल्ट्रा-लार्ज स्केल इंटीग्रेशन (ULSI) और विशाल मेमोरी स्पेस के प्रबंधन वाले उच्च-क्षमता 64-बिट माइक्रोप्रोसेसरों की जटिल वास्तुकला की तैनाती का स्पष्ट रूप से दावा करती है।"}},
{type:"mcq",diff:"hard",en:{q:"In the strict categorization of third-generation microchip density, an integrated circuit officially designated as Large Scale Integration (LSI) is characterized by containing roughly how many embedded components?",opts:["About 100 components","About 1000 components","About 10 components","Millions of components"],ans:0,exp:"In the rigid taxonomy of early silicon manufacturing, Integrated Circuits (ICs) were categorized by absolute density. A chip classified explicitly as Large Scale Integration (LSI) packed roughly 100 discrete components. Scaling dramatically past 1,000 components breached the threshold into Very Large Scale Integration (VLSI)."},hi:{q:"तीसरी पीढ़ी के माइक्रोचिप घनत्व के सख्त वर्गीकरण में, लार्ज स्केल इंटीग्रेशन (LSI) के रूप में आधिकारिक तौर पर नामित एक इंटीग्रेटेड सर्किट में लगभग कितने एम्बेडेड घटक होते हैं?",opts:["लगभग 100 घटक","लगभग 1000 घटक","लगभग 10 घटक","लाखों घटक"],ans:0,exp:"प्रारंभिक सिलिकॉन निर्माण के कठोर वर्गीकरण में, IC को पूर्ण घनत्व द्वारा वर्गीकृत किया गया था। स्पष्ट रूप से लार्ज स्केल इंटीग्रेशन (LSI) के रूप में वर्गीकृत एक चिप में लगभग 100 घटक पैक किए गए थे। 1,000 घटकों से अधिक होने पर यह VLSI बन जाता है।"}},
{type:"mcq",diff:"hard",en:{q:"Examining the physical geometries of classical motherboard interfaces, which distinct port fundamentally relies upon either a DB-25M or DB-15F 'D' style trapezoidal connector?",opts:["Parallel or Video port","Serial or USB port","LAN or Audio port","PS/2 or Serial port"],ans:0,exp:"Legacy external interfaces utilized standardized 'D-Sub' trapezoidal connectors, so named because their specific shape strictly forces a unidirectional connection. Specifically, the Parallel port typically utilizes a DB-25M, while the analog Video (VGA) port relies on a DB-15F connector."},hi:{q:"क्लासिकल मदरबोर्ड इंटरफेस की भौतिक ज्यामिति की जांच करने पर, कौन सा अलग पोर्ट मौलिक रूप से DB-25M या DB-15F 'D' स्टाइल ट्रेपोजॉइडल कनेक्टर पर निर्भर करता है?",opts:["समानांतर या वीडियो पोर्ट (Parallel or Video port)","सीरियल या यूएसबी पोर्ट","LAN या ऑडियो पोर्ट","PS/2 या सीरियल पोर्ट"],ans:0,exp:"लिगेसी बाहरी इंटरफेस मानकीकृत 'D-Sub' कनेक्टर का उपयोग करते थे, जिनका नाम इसलिए रखा गया क्योंकि उनका विशिष्ट आकार सख्ती से एक दिशात्मक कनेक्शन को मजबूर करता है। विशेष रूप से, पैरेलल पोर्ट DB-25M का उपयोग करता है, जबकि वीडियो (VGA) पोर्ट DB-15F कनेक्टर पर निर्भर करता है।"}},
{type:"mcq",diff:"hard",en:{q:"In advanced motherboard topologies, the high-speed Accelerated Graphics Port (AGP) slot is architecturally dedicated to interfacing uniquely with which specific piece of expansion hardware?",opts:["High-performance Video/Graphics card","Gigabit Ethernet LAN card","Surround sound Audio card","SATA hardware RAID controller"],ans:0,exp:"The AGP (Accelerated Graphics Port) was a heavily specialized, high-bandwidth point-to-point expansion slot explicitly engineered by Intel. Unlike the shared PCI bus, AGP was dedicated entirely to attaching high-performance Video cards to dramatically accelerate complex 3D rendering."},hi:{q:"उन्नत मदरबोर्ड टोपोलॉजी में, हाई-स्पीड एक्सेलेरेटेड ग्राफिक्स पोर्ट (AGP) स्लॉट किस विशिष्ट विस्तार हार्डवेयर (expansion hardware) के साथ विशिष्ट रूप से इंटरफेस करने के लिए समर्पित है?",opts:["उच्च प्रदर्शन वाला वीडियो/ग्राफिक्स कार्ड","गीगाबिट ईथरनेट लैन कार्ड","सराउंड साउंड ऑडियो कार्ड","SATA हार्डवेयर RAID कंट्रोलर"],ans:0,exp:"AGP (Accelerated Graphics Port) एक अत्यधिक विशिष्ट, उच्च-बैंडविड्थ पॉइंट-टू-पॉइंट एक्सपेंशन स्लॉट था जिसे विशेष रूप से इंटेल द्वारा इंजीनियर किया गया था। साझा PCI बस के विपरीत, AGP पूरी तरह से उच्च प्रदर्शन वाले वीडियो कार्ड संलग्न करने के लिए समर्पित था।"}},
{type:"mcq",diff:"hard",en:{q:"In the complex terminology of logical hard disk division, what does the explicit acronym EBR physically represent?",opts:["Extended Boot Record","External Boot Record","Executable Boot Record","Essential Boot Record"],ans:0,exp:"EBR stands precisely for Extended Boot Record. In an intricate partitioned disk hierarchy, an EBR acts as the logical first sector residing at the start of an Extended Partition, holding a nested partition table listing the subsequent Logical Partitions contained within."},hi:{q:"लॉजिकल हार्ड डिस्क डिवीजन की जटिल शब्दावली में, स्पष्ट संक्षिप्त नाम EBR भौतिक रूप से क्या दर्शाता है?",opts:["एक्सटेंडेड बूट रिकॉर्ड (Extended Boot Record)","एक्सटर्नल बूट रिकॉर्ड","एक्सेक्यूटेबल बूट रिकॉर्ड","एसेंशियल बूट रिकॉर्ड"],ans:0,exp:"EBR का अर्थ एक्सटेंडेड बूट रिकॉर्ड है। एक जटिल विभाजित डिस्क पदानुक्रम में, एक EBR विस्तारित विभाजन की शुरुआत में रहने वाले तार्किक पहले सेक्टर के रूप में कार्य करता है, जिसमें एक नेस्टेड विभाजन तालिका होती है जो उसके भीतर निहित तार्किक विभाजनों को सूचीबद्ध करती है।"}},
{type:"mcq",diff:"hard",en:{q:"Focusing rigorously on traditional ATX power supply parameters, the SMPS explicitly steps down standard AC mains power into which precise array of multiplexed DC output voltages?",opts:["+/-12V, +/-5V, and 3.3V DC","+/-15V, +/-5V, and 2.5V DC","+/-9V, +/-3V, and 1.5V DC","+/-24V, +/-12V, and 5V DC"],ans:0,exp:"The internal Switched Mode Power Supply (SMPS) is a complex power converter. It intercepts 110/220V AC input and stringently steps it down, filtering it into a precise, highly stable array of DC outputs: specifically +/-12 Volts, +/-5 Volts, and exactly 3.3 Volts required by sensitive digital logic circuits."},hi:{q:"पारंपरिक ATX बिजली आपूर्ति मापदंडों पर कड़ाई से ध्यान केंद्रित करते हुए, SMPS स्पष्ट रूप से मानक AC मेन पावर को मल्टीप्लेक्स डीसी आउटपुट वोल्टेज के किस सटीक सरणी में कम करता है?",opts:["+/-12V, +/-5V, और 3.3V DC","+/-15V, +/-5V, और 2.5V DC","+/-9V, +/-3V, और 1.5V DC","+/-24V, +/-12V, और 5V DC"],ans:0,exp:"आंतरिक स्विच्ड मोड पावर सप्लाई (SMPS) एक जटिल पावर कनवर्टर है। यह 110/220V AC इनपुट को रोकता है और इसे कम करके, इसे DC आउटपुट की एक सटीक सरणी में फ़िल्टर करता है: विशेष रूप से +/-12 वोल्ट, +/-5 वोल्ट, और ठीक 3.3 वोल्ट।"}},
{type:"tf",diff:"hard",en:{q:"In fifth-generation computer chips, a single Ultra-Large Scale Integration (ULSI) package is officially defined as containing exactly one thousand embedded transistors.",opts:["True","False"],ans:1,exp:"This statement is completely false. While Very Large Scale Integration (VLSI) chips broke the 1,000 component barrier, Ultra-Large Scale Integration (ULSI) architecture exponentially dwarfs that, integrating literally millions of individual microscopic transistors into a single silicon die."},hi:{q:"पांचवीं पीढ़ी के कंप्यूटर चिप्स में, एक सिंगल अल्ट्रा-लार्ज स्केल इंटीग्रेशन (ULSI) पैकेज को आधिकारिक तौर पर ठीक एक हजार एम्बेडेड ट्रांजिस्टर वाले के रूप में परिभाषित किया गया है।",opts:["सही","गलत"],ans:1,exp:"यह कथन पूरी तरह से गलत है। जबकि वेरी लार्ज स्केल इंटीग्रेशन (VLSI) चिप्स ने 1,000 घटक बाधा को तोड़ दिया, अल्ट्रा-लार्ज स्केल इंटीग्रेशन (ULSI) वास्तुकला लाखों व्यक्तिगत सूक्ष्म ट्रांजिस्टर को एक एकल सिलिकॉन डाई में एकीकृत करता है।"}},
{type:"tf",diff:"hard",en:{q:"During the absolute initial phase of a computer's boot sequence, the BIOS firmly mandates reading the Master Boot Record (MBR) before ever conducting the Power-On Self-Test (POST).",opts:["True","False"],ans:1,exp:"This is completely false. The architectural sequence is immovable: upon power-on, the BIOS instantly conducts the POST to verify critical hardware integrity first. Only if the POST passes successfully does the BIOS subsequently seek out and read the MBR to initiate OS loading."},hi:{q:"कंप्यूटर के बूट अनुक्रम के पूर्ण प्रारंभिक चरण के दौरान, BIOS पावर-ऑन सेल्फ-टेस्ट (POST) आयोजित करने से पहले ही मास्टर बूट रिकॉर्ड (MBR) को पढ़ना मजबूती से अनिवार्य करता है।",opts:["सही","गलत"],ans:1,exp:"यह पूरी तरह से गलत है। वास्तुशिल्प अनुक्रम अचल है: चालू होने पर, BIOS पहले महत्वपूर्ण हार्डवेयर अखंडता को सत्यापित करने के लिए तुरंत POST आयोजित करता है। यदि POST सफलतापूर्वक पास हो जाता है, तभी BIOS बाद में OS लोडिंग शुरू करने के लिए MBR को पढ़ता है।"}}
];
